window.__dh_data["hi"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "धम्मपद",
  "chaps": "अध्याय",
  "fontsize": "फ़ॉन्ट का आकार",
  "chap1": "यमक",
  "1": "मन सभी धर्मों (प्रवृत्तियों) का अगुआ है, मन ही प्रधान है, सभी धर्म मनोमय हैं। जब कोई व्यक्ति अपने मन को मैला करके कोई वाणी बोलता है, अथवा शरीर से कोई कर्म करता है, तब दुःख उसके पीछे ऐसे हो लेता है, जैसे गाड़ी के चक्के बैल के पैरों के पीछे-पीछे हो लेते हैं।",
  "2": "मन सभी धर्मों (प्रवृत्तियों) का अगुआ है, मन ही प्रधान है, सभी धर्म मनोमय हैं। जब कोई व्यक्ति अपने मन को उजला रखकर कोई वाणी बोलता है, अथवा शरीर से कोई कर्म करता है, तब सुख उसके पीछे ऐसे हो लेता है जैसे कभी संग न छोड़ने वाली छाया संग-संग चलने लगती है।",
  "3": "'मुझे कोसा', 'मुझे मारा', 'मुझे हराया', 'मुझे लूटा'जो मन में ऐसी गाँठें बाँधते रहते हैं, उनका वैर शांत नहीं होता।",
  "4": "'मुझे कोसा', 'मुझे मारा', 'मुझे हराया', 'मुझे लूटा'जो मन में ऐसी गाँठें नहीं बाँधते हैं, उनका वैर शांत हो जाता है।",
  "5": "यहाँ (इस लोक में) कभी भी वैर से वैर शांत नहीं होते, बल्कि अवैर से शांत होते हैं। यही सनातन धर्म है।",
  "6": "अनाड़ी लोग नहीं जानते कि हम यहाँ (इस संसार) से जाने वाले हैं। जो इसे जान लेते हैं उनके झगड़े शांत हो जाते हैं।",
  "7": "अच्छी लगने वाली चीजों को शुभ ही शुभ देखते विहार करने वाले, इंद्रियों में असंयत, भोजन की मात्रा के अजानकार, आलसी और उद्योगहीन को मार ऐसे सताता है जैसे दुर्बल वृक्ष को मारुत (पवन)।",
  "8": "अशुभ को अशुभ जानकर साधना करने वाले, इंद्रियों में सुसंयत, भोजन की मात्रा के जानकार, श्रद्धावान और उद्योगरत को मार उसी प्रकार नहीं डिगा सकता जैसे कि वायु शैल पर्वत को।",
  "9": "जिसने कषायों (चित्तमलों) का परित्याग नहीं किया है पर काषाय वस्त्र धारण किए हुए है, वह संयम और सत्य से परे है। वह काषाय वस्त्र (धारण करने) का अधिकारी नहीं है।",
  "10": "जिसने कषायों (चित्तमलों) को निकाल बाहर किया है, शीलों में प्रतिष्ठित है, संयम और सत्य से युक्त है, वह निःसंदेह काषाय वस्त्र (धारण करने) का अधिकारी है।",
  "11": "जो निःसार को सार और सार को निःसार समझते हैं, ऐसे गलत चिंतन में लगे हुए व्यक्तियों को सार प्राप्त नहीं होता।",
  "12": "सार को सार और निःसार को निःसार जानकर शुद्ध चिंतन वाले व्यक्ति सार को प्राप्त कर लेते हैं।",
  "13": "जैसे बुरी तरह छाए हुए घर में वर्षा का पानी घुस जाता है, वैसे ही अभावित चित्त में राग घुस जाता है।",
  "14": "जैसे अच्छी तरह छाए हुए घर में वर्षा का पानी नहीं घुस पाता है, वैसे ही (शमथ और विपश्यना से) अच्छी तरह भावित चित्त में राग नहीं घुस पाता है।",
  "15": "यहाँ (इस लोक में) शोक करता है, मरणोपरांत (परलोक में) शोक करता है, पाप करने वाला (व्यक्ति) दोनों जगह शोक करता है। वह अपने कर्मों की मलिनता देखकर शोकापन्न होता है, संतापित होता है।",
  "16": "यहाँ (इस लोक में) प्रसन्न होता है, मरणोपरांत (परलोक में) प्रसन्न होता है, पुण्य किया हुआ व्यक्ति दोनों जगह प्रसन्न होता है। वह अपने कर्मों की शुद्धता (पुण्यकर्म संपत्ति) देखकर मुदित होता है, प्रमुदित होता है।",
  "17": "यहाँ (इस लोक में) संतप्त होता है, प्राण छोड़कर (परलोक में) संतप्त होता है। पापकारी दोनों जगह संतप्त होता है। 'मैंने पाप किया है'इस चिंतन से संतप्त होता है (और) दुर्गति को प्राप्त होकर और भी अधिक संतप्त होता है।",
  "18": "यहाँ (इस लोक में) आनंदित होता है, प्राण छोड़कर (परलोक में) आनंदित होता है। पुण्यकारी दोनों जगह आनंदित होता है। 'मैंने पुण्य किया है'इस चिंतन से आनंदित होता है (और) सुगति को प्राप्त होने पर और भी अधिक आनंदित होता है।",
  "19": "धर्मग्रंथों (तिपिटक) का कितना ही पाठ करे, लेकिन यदि प्रमाद के कारण मनुष्य उन धर्मग्रंथों के अनुसार आचरण नहीं करता, तो दूसरों की गौवें गिनने वाले ग्वालों की तरह वह श्रमणत्व का भागी नहीं होता।",
  "20": "धर्मग्रंथों का भले थोड़ा ही पाठ करे, लेकिन यदि वह व्यक्ति धर्म के अनुकूल आचरण करने वाला होता है, तो राग, द्वेष और मोह को त्यागकर, संप्रज्ञानी बन, भली प्रकार विमुक्त चित्त वाला होकर, इहलोक अथवा परलोक में कुछ भी आसक्ति न करता हुआ श्रमणत्व का भागी हो जाता है।",
  "chap2": "अप्रमाद",
  "21": "प्रमाद न करना अमृत (निर्वाण) का पद है और प्रमाद मृत्यु का पद। प्रमाद न करने वाले (कभी) मरते नहीं और प्रमादी (तो) मरे-समान होते हैं।",
  "22": "ज्ञानी जन अप्रमाद के बारे में इस प्रकार विशेष रूप से जानकर आर्यों की गोचरभूमि में रमण करते हुए अप्रमाद में प्रमुदित होते हैं।",
  "23": "वे सतत ध्यान करने वाले, नित्य दृढ़ पराक्रम करने वाले, धीर पुरुष उत्कृष्ट योगक्षेम वाले निर्वाण को प्राप्त (अर्थात, इसका साक्षात्कार) कर लेते हैं।",
  "24": "उद्योगशील, स्मृतिमान, शुचि (दोषरहित) कर्म करने वाले, सोच-समझकर काम करने वाले, संयमी, धर्म का जीवन जीने वाले, अप्रमत्त (व्यक्ति) का यश खूब बढ़ता है।",
  "25": "मेधावी (पुरुष) उद्योग, अप्रमाद, संयम तथा (इंद्रियों के) दमन द्वारा (अपने लिए ऐसा) द्वीप बना ले जिसे (चार प्रकार के क्लेशों की) बाढ़ आप्लावित न कर सके।",
  "26": "मूर्ख, दुर्बुद्धि जन प्रमाद में लगे रहते हैं, (जबकि) मेधावी श्रेष्ठ धन के समान अप्रमाद की रक्षा करता है।",
  "27": "प्रमाद मत करो और न ही कामभोगों में लिप्त होओ, क्योंकि अप्रमादी ध्यान करते हुए महान (निर्वाण) सुख को पा लेता है।",
  "28": "जब कोई समझदार व्यक्ति प्रमाद को अप्रमाद से परे धकेल देता (अर्थात, जीत लेता) है, तब वह प्रज्ञारूपी प्रासाद पर चढ़ा हुआ शोक रहित हो जाता है। (ऐसा) शोक रहित धीर (मनुष्य) शोक ग्रस्त (विमूढ़) जनों को ऐसे ही (करुण भाव से) देखता है जैसे कि पर्वत पर खड़ा हुआ (कोई व्यक्ति) धरती पर खड़े हुए लोगों को देखे।",
  "29": "प्रमाद करने वालों में अप्रमादी (क्षीणाश्रव) तथा (अज्ञान की नींद में) सोए लोगों में (प्रज्ञा में) अतिसचेत उत्तम प्रज्ञा वाला (दूसरों को) पीछे छोड़कर (ऐसे आगे निकल जाता है) जैसे शीघ्रगामी अश्व दुर्बल अश्व को।",
  "30": "अप्रमाद के कारण इंद्र देवताओं में श्रेष्ठता को प्राप्त हुआ। (पंडित जन) अप्रमाद की प्रशंसा करते हैं, और प्रमाद की सदा निंदा होती है।",
  "31": "जो साधक अप्रमाद में रत रहता है, या प्रमाद में भय देखता है, वह अपने छोटे-बड़े सभी (कर्म-संस्कारों के) बंधनों को आग की भाँति जलाते हुए चलता है।",
  "32": "जो साधक अप्रमाद में रत रहता है, या प्रमाद में भय देखता है, उसका पतन नहीं हो सकता। वह (तो) निर्वाण के समीप (पहुँचा हुआ) होता है।",
  "chap3": "चित्त",
  "33": "चंचल, चपल, कठिनाई से संरक्षण और कठिनाई से (ही) निवारण योग्य चित्त को मेधावी (पुरुष) वैसे ही सीधा करता है जैसे बाण बनाने वाला बाण को।",
  "34": "जैसे जल से निकालकर धरती पर फेंकी गई मछली तड़फड़ाती है, वैसे ही मार के फंदे से निकलने के लिए यह चित्त (तड़फड़ाता है)।",
  "35": "ऐसे चित्त का दमन करना अच्छा है जिसको वश में करना कठिन है, जो शीघ्रगामी है और जहाँ चाहे वहाँ चला जाता है। दमन किया गया चित्त सुख देने वाला होता है।",
  "36": "जो बड़ा दुर्दर्श है, कठिनाई से दिखाई पड़ने वाला है, बड़ा चालाक है, जहाँ चाहे वहीं जा पहुँचता है, समझदार (व्यक्ति) को चाहिए कि (ऐसे) चित्त की रक्षा करे। सुरक्षित चित्त बड़ा सुखदायी होता है।",
  "37": "जो (कोई) दूरगामी, अकेला विचरने वाले, शरीर-रहित, गुहाशायी चित्त को संयमित करेंगे, वे मार के बंधन से मुक्त हो जाएँगे।",
  "38": "जिसका चित्त अस्थिर है, जो सद्धर्म को नहीं जानता, जिसकी श्रद्धा दोलायमान (डाँवाडोर) है, उसकी प्रज्ञा परिपूर्ण नहीं हो सकती।",
  "39": "जिसके चित्त में राग नहीं, जिसका चित्त द्वेष से रहित है, जो पाप-पुण्य-विहीन है, उस सजग रहने वाले (क्षीणाश्रव) को कोई भय नहीं होता।",
  "40": "इस शरीर को घड़े के समान (भंगुर) जान, और इस चित्त को गढ़ के समान (रक्षित और दृढ़) बना, प्रज्ञारूपी शस्त्र के साथ मार से युद्ध करे। (उसे) जीत लेने पर भी (चित्त की) रक्षा करे और अनासक्त बना रहे।",
  "41": "अहो! यह तुच्छ शरीर शीघ्र ही चेतनारहित होकर निरर्थक काठ के टुकड़े की भाँति पृथ्वी पर पड़ रहेगा।",
  "42": "शत्रु शत्रु की अथवा वैरी वैरी को जितनी हानि करता है, कुमार्ग पर लगा हुआ चित्त उससे (कहीं) अधिक हानि करता है।",
  "43": "जितनी (भलाई) न माता-पिता कर सकते हैं, न दूसरे भाई-बंधु, उससे (कहीं अधिक) भलाई सन्मार्ग पर लगा हुआ चित्त करता है।",
  "chap4": "पुष्प",
  "44": "कौन है जो इस (आत्मभाव अथवा अपनापे रूपी) पृथ्वी, और देवताओं सहित इस यमलोक को (बींध कर इनका) साक्षात्कार कर लेगा? कौन कुशल (व्यक्ति) भली प्रकार उपदिष्ट धर्म के पदों का पुष्प की भाँति (चयन करते हुए इनको भी बींध कर इनका) साक्षात्कार कर पाएगा?",
  "45": "शैक्ष्य (निर्वाण की खोज में लगा हुआ व्यक्ति) ही पृथ्वी पर, और देवताओं सहित इस यमलोक पर, विजय पाएगा। शैक्ष्य (ही) भली प्रकार उपदिष्ट धर्म के पदों का पुष्प की भाँति चयन करेगा।",
  "46": "इस शरीर को फेन (झाग) के समान (या) (मरु-) मरीचिका के समान (निःसार) जानकर मार के फंदों को काटकर मृत्युराज की दृष्टि से ओझल रहे।",
  "47": "(कामभोगरूपी) पुष्पों को चुनने वाले, आसक्तियों में डूबे हुए मनुष्य को मृत्यु (वैसे ही) पकड़ कर ले जाती है जैसे सोए हुए गाँव को (नदी की) बड़ी बाढ़ (बहा ले जाती है)।",
  "48": "(कामभोगरूपी) पुष्पों को चुनने वाले, आसक्तियों में डूबे हुए मनुष्य को (जबकि अभी वह) कामनाओं से तृप्त नहीं हुआ है, यमराज अपने वश में कर लेता है।",
  "49": "जैसे भ्रमर फूल के वर्ण और गंध को क्षति पहुँचाए बिना रस को लेकर चल देता है, वैसे ही गाँव में मुनि भिक्षाटन करे।",
  "50": "दूसरों के परुष (मर्मच्छेदक) वचनों पर ध्यान न दे, न दूसरों के कृत-अकृत को देखे, (तद्विपरीत) अपने (ही) कृत-अकृत को देखे।",
  "51": "जैसे कोई पुष्प सुंदर और वर्णयुक्त होने पर भी गंधरहित हो, वैसे ही अच्छी कही हुई (बुद्ध) वाणी होती है फलरहित, यदि कोई तदनुसार (आचरण) न करे।",
  "52": "जैसे कोई पुष्प सुंदर और वर्णयुक्त हो और (सु-) गंध वाला हो, वैसे ही अच्छी कही हुई (बुद्ध) वाणी होती है फलसहित, यदि कोई तदनुसार (आचरण) करने वाला हो।",
  "53": "जैसे (कोई व्यक्ति) पुष्प-राशि से बहुत सी मालाएँ बनाए, ऐसे ही उत्पन्न हुए प्राणी को बहुत-सा कुशलकर्म (पुण्य) करना चाहिए।",
  "54": "चंदन, तगर, कमल अथवा जूहीइन (सभी) की सुगंधों से शील-सदाचार की सुगंध बढ़-चढ़ कर है।",
  "55": "तगर और चंदन की गंध, उत्पल (कमल) और चमेली की गंधइन भिन्न-भिन्न सुगंधियों से शील की गंध अधिक श्रेष्ठ है।",
  "56": "तगर और चंदन की जो यह गंध फैलती है, वह अल्पमात्र है, और जो यह शीलवानों की गंध है, वह उत्तम (गंध) देवताओं में फैलती है।",
  "57": "जो शीलसंपन्न हैं, प्रमादरहित होकर विहार करते हैं, यथार्थ ज्ञान द्वारा मुक्त हो चुके हैं, उनके मार्ग को मार नहीं देख पाता।",
  "58": "जिस प्रकार महापथ पर फेंके गए कचरे के ढेर में पवित्र गंध वाला मनोरम पद्म उत्पन्न हो जाता है,",
  "59": "उसी प्रकार (कचरे के समान) भगवान सम्यक्संबुद्ध का श्रावक भी अपनी प्रज्ञा से अंधे पृथग्जनों के बीच अत्यंत शोभायमान होता है।",
  "chap5": "बाल",
  "60": "जागने वाले को रात लंबी हो जाती है, थके हुए का योजन लंबा हो जाता है। सद्धर्म को न जानने वाले मूर्ख (व्यक्तियों) के लिए संसार-चक्र लंबा हो जाता है।",
  "61": "यदि विचरण करते हुए (शील, समाधि, प्रज्ञा में) अपने से श्रेष्ठ या अपने सदृश (सहचर) न मिले, तो दृढ़ता के साथ अकेला ही विचरण करे। मूर्ख (व्यक्ति) से सहायता नहीं मिल सकती।",
  "62": "मेरे पुत्र! मेरा धन!इस (मिथ्या चिंतन) में ही मूढ़ व्यक्ति व्याकुल बना रहता है। अरे, जब यह (तन और मन का) अपनापा ही अपना नहीं है, तो कहाँ मेरे पुत्र? कहाँ मेरा धन?",
  "63": "जो मूढ़ होकर (अपनी) मूढ़ता को स्वीकारता है, वह इस (अंश) में पंडित (ज्ञानी) है; और जो मूढ़ होकर (अपने आप को) पंडित मानता है, वह 'मूढ़' ही कहा जाता है।",
  "64": "चाहे मूढ़ (व्यक्ति) जीवन-भर पंडित की सेवा में रहे, वह धर्म को (वैसे ही) नहीं जान पाता जैसे कलछी सूप के रस को।",
  "65": "चाहे विज्ञ पुरुष मुहूर्त भर ही पंडित की सेवा में रहे, वह शीघ्र ही धर्म को (वैसे) जान लेता है जैसे जिह्वा सूप के रस को।",
  "66": "बाल-बुद्धि वाले मूर्ख जन अपने ही शत्रु बनकर आचरण करते हैं और ऐसे पापकर्म करते हैं जिनका फल (स्वयं उनके अपने लिए ही) कड़वा होता है।",
  "67": "वह किया हुआ कर्म ठीक नहीं जिसे करके पीछे पछताना पड़े, और जिसके फल को अश्रुमुख हो रोते हुए भोगना पड़े।",
  "68": "और वह किया हुआ कर्म ठीक होता है जिसे करके पीछे पछताना न पड़े, और जिसके फल को प्रसन्नचित्त होकर अच्छे मन से भोगा जा सके।",
  "69": "जब तक पाप का फल नहीं आता तब तक मूढ़ (व्यक्ति) उसे मधु के समान (मधुर) मानता है, और जब पाप का फल आता है तब (वह) मूढ़ दुःखी होता है।",
  "70": "चाहे मूढ़ (व्यक्ति) महीना-महीना (के अंतराल) पर केवल कुश की नोक से भोजन करे, तो भी वह धर्मवेत्ताओं (की कुशल चेतना) के सोलहवें भाग की बराबरी भी नहीं कर सकता।",
  "71": "जैसे ताजा दूध शीघ्र नहीं जमता, उसी तरह किया गया पाप कर्म शीघ्र (अपना) फल नहीं लाता. राख से ढकी आग की तरह जलता हुआ वह मूर्ख का पीछा करता है।",
  "72": "मूढ़ का जितना भी ज्ञान है (वह उसके) अनिष्ट के लिए होता है। वह उसकी मूर्धा (सिर/प्रज्ञा) को गिराकर उसके कुशल कर्मों का नाश कर डालता है।",
  "73": "(मूढ़ व्यक्ति) जो नहीं है उसकी संभावना जगाता है, भिक्षुओं में अग्रणी (बनना चाहता है), संघ के आवासों (विहारों) का स्वामित्व (चाहता है) और पराये कुलों में आदर-सत्कार की कामना करता है।",
  "74": "गृहस्थ और प्रव्रजित दोनों मेरा ही किया मानें, किसी भी कृत्य-अकृत्य में मेरे ही वशवर्ती रहेंऐसा मूढ़ (व्यक्ति) का संकल्प होता है। (इससे) उसकी इच्छा और अभिमान का संवर्द्धन होता है।",
  "75": "लाभ का मार्ग दूसरा है और निर्वाण की ओर ले जाने वाला दूसराइस प्रकार इसे भली प्रकार जानकर बुद्ध का श्रावक भिक्षु (आदर-) सत्कार की इच्छा न करे और (त्रिविध) विवेक (अर्थात काय विवेक, चित्त विवेक, विक्खम्भन विवेक) को बढ़ावा दे।",
  "chap6": "पण्डित",
  "76": "जो व्यक्ति अपना दोष दिखाने वाले को (भूमि में छिपी) संपदा दिखाने वाले की तरह समझे, जो संयम की बात करने वाले मेधावी पंडित की संगति करे, उस व्यक्ति का मंगल ही होता है, अमंगल नहीं।",
  "77": "जो उपदेश दे, अनुशासन करे, अनुचित कार्य से रोके, वह सत्पुरुषों का प्रिय होता है और असत्पुरुषों का अप्रिय।",
  "78": "न पापी मित्रों की संगति करे, न अधम पुरुषों की। संगति करे कल्याणमित्रों की, उत्तम पुरुषों की।",
  "79": "बुद्ध के उपदेशित धर्म में सदा रमण करता है पंडित। (नवविध लोकोत्तर) धर्म (रस) का पान करने वाला विशुद्धचित्त हो सुखपूर्वक विहार करता है।",
  "80": "पानी ले जाने वाले (जिधर चाहते हैं, उधर ही से) पानी को ले जाते हैं, बाण बनाने वाले बाण को (तपाकर) सीधा करते हैं, बढ़ई लकड़ी को (अपनी रुचि के अनुसार) सीधा या बाँका करते हैं, और पंडित (जन) अपना (ही) दमन करते हैं।",
  "81": "जैसे सघन शैल-पर्वत वायु से प्रकंपित नहीं होता, वैसे ही समझदार लोग निंदा और प्रशंसा (वस्तुतः, आठों लोक धर्मों) से विचलित नहीं होते।",
  "82": "देशना-धर्मों को सुनकर पंडित (जन) गहरे, स्वच्छ, निर्मल सरोवर के समान अत्यंत प्रसन्न (संतुष्ट) होते हैं।",
  "83": "सत्पुरुष सर्वत्र (पाँचों स्कंधों में) छंदराग छोड़ देते हैं। संत जन कामभोगों के लिए बात नहीं चलाते। चाहे सुख मिले या दुःख, पंडित (जन) (अपने मन का) उतार-चढ़ाव प्रदर्शित नहीं करते।",
  "84": "जो अपने लिए या दूसरे के लिए पुत्र, धन अथवा राज्य की कामना नहीं करता और न अधर्म से अपनी उन्नति चाहता है, वह शीलवान, प्रज्ञावान और धार्मिक होता है।",
  "85": "मनुष्यों में (भवसागर से) पार जाने वाले लोग विरले ही होते हैं। ये दूसरे लोग तो (सत्कायदृष्टिरूपी) तट पर ही दौड़ने वाले होते हैं।",
  "86": "जो लोग सम्यक प्रकार से आख्यात धर्म का अनुवर्तन करते हैं, वे अति दुस्तर मृत्यु-क्षेत्र के पार चले जाएँगे।",
  "87": "पंडित कृष्ण धर्म को त्यागकर शुक्ल (धर्म) की भावना करे (अर्थात, पापकर्म को छोड़कर शुभ कर्म करे)। वह घर से बेघर होकर (सामान्य व्यक्ति के लिए) आकर्षणरहित एकांत का सेवन करे।",
  "88": "कामनाओं को त्यागकर अकिंचन (बना हुआ व्यक्ति) वहीं (उसी अवस्था में) रमण करने की इच्छा करे। समझदार (व्यक्ति) (पाँच नीवरणरूपी) चित्त-मलों से अपने आपको परिशुद्ध करे।",
  "89": "संबोधि के अंगों में जिनका चित्त सम्यक प्रकार से भावित (अभ्यस्त) हो गया है, जो परिग्रह का परित्याग कर अपरिग्रह में रत हैं, आश्रवों (चित्तमलों) से रहित ऐसे द्युतिमान (पुरुष ही) लोक में निर्वाण-प्राप्त हैं।",
  "chap7": "अरहन्त",
  "90": "जिसकी यात्रा पूरी हो गई है, जो शोक रहित है, सर्वथा विमुक्त है, जिसकी सभी ग्रंथियाँ कट गई हैं, उसके लिए (कायिक और चैतसिक) संताप (नाम की कोई चीज) नहीं है।",
  "91": "स्मृतिमान उद्योग करते रहते हैं, वे घर में रमण नहीं करते। जैसे हंस क्षुद्र जलाशय को छोड़कर चले जाते हैं, वैसे ही वे घर-बार (अथवा, सभी ठौर-ठिकानों को) छोड़ देते हैं।",
  "92": "जो (कर्मों और प्रत्ययों का) संचय नहीं करते, जिन्हें (अपने) आहार (की मात्रा का) पूरा-पूरा ज्ञान है, शून्यतास्वरूप तथा निमित्तरहित निर्वाण जिनकी गोचरभूमि है, उनकी गति वैसे ही अज्ञेय रहती है जैसे आकाश में पक्षियों की (गति)।",
  "93": "जिसके आश्रव (चित्त-मल) पूरी तरह से क्षीण हो गए हैं, जो आहार में आसक्त नहीं है, शून्यतास्वरूप तथा निमित्तरहित निर्वाण जिनकी गोचरभूमि है, उनकी गति वैसे ही अज्ञेय रहती है जैसे आकाश में पक्षियों की (गति)।",
  "94": "सारथि द्वारा सुदांत (सुशिक्षित) घोड़ों के समान जिसकी इंद्रियाँ शांत हो गई हैं, जिसका अभिमान विगलित हो गया है, जो आश्रवरहित है, देवगण भी वैसे (व्यक्ति) की स्पृहा करते हैं।",
  "95": "सुंदर व्रतधारी अर्हत् (तादि) पृथ्वी के समान क्षुब्ध न होने वाला और इंद्रकील के समान अकम्प्य होता है। वैसे (व्यक्ति) को कर्दमरहित जलाशय की भाँति संसार (-मल) नहीं होते।",
  "96": "सम्यक ज्ञान द्वारा मुक्त हुए उपशांत (अरहंत) का मन शांत हो जाता है, और वाणी तथा कर्म भी शांत हो जाते हैं।",
  "97": "जो नर (अंध-) श्रद्धारहित, निर्वाण का जानकार, (भव-संसरण की) संधि का छेदन किए हुए, (पुनर्जन्म की) संभावनारहित और (सर्वप्रकार की) आशाएँ त्यागे हुए हो, वह निःसंदेह उत्तम पुरुष होता है।",
  "98": "गाँव हो या जंगल, भूमि नीची हो या ऊँची, जहाँ (कहीं) अरहंत विहार करते हैं, वह भूमि रमणीय होती है।",
  "99": "रमणीय वन जहाँ (सामान्य) व्यक्ति रमण नहीं करते, (वहाँ) वीतराग (क्षीणाश्रव) रमण करेंगे क्योंकि वे कामभोगों की खोज में नहीं रहते।",
  "chap8": "सहस्र",
  "100": "निरर्थक पदों से युक्त हजार वचनों की अपेक्षा एक (अकेला) सार्थक पद श्रेयस्कर होता है जिसे सुनकर (कोई व्यक्ति) (रागादि के उपशमन से) शांत हो जाता है।",
  "101": "निरर्थक पदों से युक्त हजार गाथाओं की अपेक्षा वह एक अकेला सार्थक गाथापद श्रेयस्कर होता है, जिसे सुनकर कोई व्यक्ति शांत हो जाता है।",
  "102": "जो कोई निरर्थक पदों से युक्त सौ गाथाएँ बोले, उसकी अपेक्षा एक अकेला सार्थक धर्मपद श्रेयस्कर होता है, जिसे सुनकर कोई व्यक्ति शांत हो जाता है।",
  "103": "हजारों हजार मनुष्यों को संग्राम में जीतने वाले से भी एक अपने आपको जीतने वाला कहीं उत्तम संग्राम-विजेता होता है।",
  "104": "इन अन्य लोगों को (द्यूत, धन-हरण, संग्राम अथवा बलाभिभव द्वारा) जीतने की अपेक्षा अपने आपको जीतना ही श्रेयस्कर है। जिस व्यक्ति ने स्वयं को दान्त बना लिया है और जो अपने आपको नित्य संयत रखता है",
  "105": "उस प्रकार के व्यक्ति की जीत को न तो देव, न गंधर्व और न ही ब्रह्मा सहित मार ही पराजय में बदल सकते हैं।",
  "106": "जो कोई सौ वर्षों तक महीने-महीने हजार रुपये से यज्ञ करे और (स्रोतापन्न से लेकर क्षीणाश्रव तक) किसी भावितात्म व्यक्ति की मुहूर्त-भर ही पूजा कर ले, तो सौ वर्षों के यज्ञ की अपेक्षा वह मुहूर्त-भर की पूजा ही श्रेयस्कर होती है।",
  "107": "जो कोई व्यक्ति सौ वर्षों तक वन में अग्निहोत्र करे और किसी भावितात्म व्यक्ति की मुहूर्त भर ही पूजा कर ले, तो सौ वर्षों के हवन से वह मुहूर्त भर की पूजा ही श्रेयस्कर होती है।",
  "108": "पुण्य की इच्छा से जो कोई संसार में वर्ष-भर यज्ञ-हवन करे, तो भी वह (स्रोतापन्न से लेकर क्षीणाश्रव की किसी अवस्था को प्राप्त) सरलचित्त व्यक्तियों को किए जाने वाले अभिवादन के चतुर्थांश के बराबर भी नहीं होता।",
  "109": "जो अभिवादनशील है और नित्य बड़े-बूढ़ों की सेवा करता है, उसकी ये चार बातें बढ़ती हैंआयु, वर्ण, सुख और बल।",
  "110": "दुःशील और चित्त की एकाग्रता से रहित व्यक्ति के सौ वर्ष के जीवन से शीलवान और ध्यानी व्यक्ति का एक दिन का जीवन श्रेयस्कर होता है।",
  "111": "दुष्प्रज्ञ और चित्त की एकाग्रता से रहित व्यक्ति के सौ वर्ष के जीवन से प्रज्ञावान और ध्यानी व्यक्ति का एक दिन का जीवन श्रेयस्कर होता है।",
  "112": "आलसी और उद्योगरहित व्यक्ति के सौ वर्ष के जीवन से दृढ़ उद्योग करने वाले व्यक्ति का एक दिन का जीवन श्रेयस्कर होता है।",
  "113": "(पंचस्कंध के) उदय-व्यय को न देखने वाले व्यक्ति के सौ वर्ष के जीवन से उदय-व्यय को देखने वाले व्यक्ति का एक दिन का जीवन श्रेयस्कर होता है।",
  "114": "अमृत-पद (निर्वाण) को न देखने वाले व्यक्ति के सौ वर्ष के जीवन से अमृत-पद को देखने वाले व्यक्ति का एक दिन का जीवन श्रेयस्कर होता है।",
  "115": "उत्तम धर्म (नवविध लोकोत्तर धर्म अर्थात चार मार्ग, चार फल और निर्वाण) को न देखने वाले व्यक्ति के सौ वर्ष के जीवन से उत्तम धर्म को देखने वाले व्यक्ति का एक दिन का जीवन श्रेयस्कर होता है।",
  "chap9": "पाप",
  "116": "पुण्य कर्म करने में जल्दी करे, पाप कर्म से चित्त को हटाए, क्योंकि धीमी गति से पुण्य कर्म करने वाले का मन पाप कर्म में लीन होने लगता है।",
  "117": "यदि पुरुष कभी पाप कर्म कर डाले, तो उसे बार-बार न करे। वह उसमें रुचि न ले, क्योंकि पाप कर्मों का संचय दुःख का कारण होता है।",
  "118": "यदि पुरुष कभी पुण्य कर्म करे, तो उसे बार-बार करे। वह उसके प्रति उत्साह जगाए, क्योंकि पुण्य कर्मों का संचय सुख का कारण होता है।",
  "119": "पापी भी पाप को तब तक अच्छा ही समझता है जब तक पाप का विपाक नहीं होता। और जब पाप का विपाक होता है, तब पापी पापों को देखने लगता है।",
  "120": "भद्र (पुण्य करने वाला व्यक्ति) भी तब तक पाप को देखता है जब तक पुण्य का विपाक नहीं होता। जब पुण्य का परिपाक होता है, तब वह भद्र व्यक्ति पुण्यों को देखने लगता है।",
  "121": "'वह मेरे पास नहीं आएगा'ऐसा सोचकर पाप की अवहेलना न करे। बूँद-बूँद पानी गिरने से घड़ा भर जाता है। ऐसे ही थोड़ा-थोड़ा संचय करता हुआ मूढ़ व्यक्ति भी पाप से भर जाता है।",
  "122": "'वह मेरे पास नहीं आएगा'ऐसा सोचकर पुण्य की अवहेलना न करे। बूँद-बूँद पानी गिरने से घड़ा भर जाता है। ऐसे ही थोड़ा-थोड़ा संचय करता हुआ धीर व्यक्ति पुण्य से भर जाता है।",
  "123": "जैसे छोटे काफिले परंतु विपुल धन वाला व्यापारी भययुक्त मार्ग को, अथवा जीवित रहने की इच्छा वाला व्यक्ति विष को छोड़ देता है, वैसे ही मनुष्य पापों को छोड़ दे।",
  "124": "यदि हाथ में व्रण (घाव) न हो तो हाथ से विष को ले सकता है, क्योंकि व्रणरहित शरीर में विष नहीं चढ़ता है। ऐसे ही पापकर्म न करने वाले को पाप नहीं लगता।",
  "125": "जो निरपराध, निर्मल, दोषरहित व्यक्ति पर दोषारोपण करता है, उस दोष लगाने वाले मूर्ख को ही पाप लगता है; जैसे कि पवन की उल्टी दिशा में फेंकी गई सूक्ष्म रज फेंकने वाले पर ही आ गिरती है।",
  "126": "कोई मनुष्य लोक में गर्भ में उत्पन्न होते हैं, पापकर्मी नरक में जाते हैं, सुगति वाले स्वर्ग में जाते हैं, और अनाश्रव (चित्तमलरहित) निर्वाण-लाभ करते हैं।",
  "127": "न अनंत आकाश में, न समुद्र की गहराइयों में, न पर्वतों की गुहा-कंदराओं में प्रवेश करकेइस जगत में कहीं भी तो ऐसा स्थान नहीं है जहाँ ठहरा हुआ कोई अपने पापकर्मों के भोगने से बच सके।",
  "128": "न अनंत आकाश में, न समुद्र की गहराइयों में, न पर्वतों की गुहा-कंदराओं में प्रवेश करकेइस जगत में कहीं भी तो ऐसा स्थान नहीं है जहाँ ठहरे हुए को मृत्यु न पकड़ ले, न दबोच ले।",
  "chap10": "दण्ड",
  "129": "सभी दंड से डरते हैं। सभी को मृत्यु से भय लगता है। अतः सभी को अपने जैसा समझकर न किसी की हत्या करे, न हत्या करने के लिए प्रेरित करे।",
  "130": "सभी दंड से डरते हैं। जीवित रहना सबको प्रिय लगता है। अतः सभी को अपने जैसा समझकर न किसी की हत्या करे, न हत्या करने के लिए प्रेरित करे।",
  "131": "जो सुख चाहने वाले प्राणियों को, अपने सुख की चाह से, दंड से विहिंसित करता है (कष्ट पहुँचाता है), वह मरकर सुख नहीं पाता।",
  "132": "जो सुख चाहने वाले प्राणियों को, अपने सुख की चाह से, दंड से विहिंसित नहीं करता, वह मरकर सुख पाता है।",
  "133": "तुम किसी को कठोर वचन मत बोलो, बोलने पर दूसरे भी तुम्हें वैसे ही बोलेंगे। क्रोध या विवाद भरी वाणी दुःख है। उसके बदले में तुम्हें दंड मिलेगा।",
  "134": "यदि तुम अपने आपको टूटे हुए काँसे के समान निःशब्द कर लो, तो समझो तुमने निर्वाण पा लिया क्योंकि तुममें कोई विवाद नहीं रह गया, कोई प्रतिवाद नहीं रह गया।",
  "135": "जैसे ग्वाला लाठी से गायों को चरागाह में हाँक कर ले जाता है, वैसे ही बुढ़ापा और मृत्यु प्राणियों की आयु को हाँक कर ले जाते हैं।",
  "136": "बाल बुद्धि वाला मूर्ख व्यक्ति पापकर्म करते हुए होश नहीं रखता। परंतु समय पाकर अपने उन्हीं कर्मों के कारण वह दुर्बुद्धि ऐसे तपता है जैसे आग से जला हो।",
  "137": "जो दंडरहितों (क्षीणाश्रवों) को दंड से पीड़ित करता है या निर्दोषों को दोष लगाता है, उसे इन दस बातों में से कोई एक बात शीघ्र ही होती है",
  "138": "(१) तीव्र वेदना, (२) हानि, (३) अंगभंग, (४) बड़ा रोग, (५) चित्तविक्षेप (उन्माद),",
  "139": "(६) राजदंड, (७) कड़ी निंदा, (८) संबंधियों का विनाश, (९) भोगों का क्षय, अथवा",
  "140": "उसके घर को आग जला डालती है। शरीर छूटने पर वह दुष्प्रज्ञ नरक में उत्पन्न होता है।",
  "141": "जिस मनुष्य के संदेह समाप्त नहीं हुए हैं, उसकी शुद्धि न नंगे रहने से, न जटा धारण करने से, न कीचड़ लपेटने से, न उपवास करने से, न कड़ी भूमि पर सोने से, न कादा पोतने से, और न उकड़ूँ बैठने से ही होती है।",
  "142": "(वस्त्र, आभूषण आदि से) अलंकृत रहते हुए भी यदि कोई शांत, दान्त, स्थिर (नियंत्रित), ब्रह्मचारी है तथा सारे प्राणियों के प्रति दंड त्याग कर समता का आचरण करता है, तो वह ब्राह्मण है, श्रमण है, भिक्षु है।",
  "143": "संसार में कोई पुरुष ऐसा भी होता है जो स्वयं ही लज्जा के मारे निषिद्ध कर्म नहीं करता। वह निंदा को नहीं सह सकता, जैसे सधा हुआ घोड़ा चाबुक को।",
  "144": "चाबुक खाए उत्तम घोड़े के समान उद्योगशील और संवेगशील बनो। श्रद्धा, शील, वीर्य, समाधि और धर्म-विनिश्चय से युक्त हो, विद्या और आचरण से संपन्न और स्मृतिमान बन इस महान दुःख-समूह का अंत कर सकोगे।",
  "145": "पानी ले जाने वाले जिधर चाहते हैं उधर ही पानी को ले जाते हैं, बाण बनाने वाले बाण को सीधा करते हैं, बढ़ई लकड़ी को सीधा या बाँका करते हैं, और सदाचार-परायण अपना ही दमन करते हैं।",
  "chap11": "जरा",
  "146": "जहाँ प्रतिक्षण सब कुछ जल ही रहा हो, वहाँ कैसी हँसी? कैसा आनंद? ऐ अविद्यारूपी अंधकार से घिरे हुए लोगो! तुम ज्ञानरूपी प्रकाश-प्रदीप को खोज क्यों नहीं करते?",
  "147": "देखो इस चित्रित शरीर को जो व्रणों से युक्त, फूला हुआ, रोगी और नाना प्रकार के संकल्पों से युक्त है और जो सदा बना रहने वाला नहीं है।",
  "148": "यह शरीर जीर्ण-शीर्ण, रोग का घर और नितांत भंगुर है। सड़ांध से भरी हुई यह देह टुकड़े-टुकड़े हो जाती है; जीवन मरणांतक जो ठहरा!",
  "149": "शरद काल की फेंकी गई लौकी के समान कुम्हलाए हुए मृत शरीर को देखकर, या कबूतरों के से वर्ण वाली हड्डियों को देखकर किसको इस देह से अनुराग होगा?",
  "150": "यह हड्डियों का नगर बना है जो मांस और रक्त से लेपा गया है; जिसमें जरा, मृत्यु, अभिमान और प्रक्ष (डाह) छिपे हुए हैं।",
  "151": "रंग-बिरंगे सुचित्रित राजरथ जीर्ण हो जाते हैं और यह शरीर भी जीर्णता को प्राप्त हो जाता है। परंतु संतों का धर्म जीर्ण नहीं होता। संतजन संतों से ऐसा ही कहते हैं।",
  "152": "अज्ञानी पुरुष बैल के समान जीर्ण होता है। उसका मांस बढ़ता है, प्रज्ञा नहीं।",
  "153": "इस काया-रूपी घर को बनाने वाले की खोज में मैं बिना रुके अनेक जन्मों तक संसरण करता रहा, किंतु बार-बार दुःखमय जन्म ही हाथ लगे।",
  "154": "ऐ घर बनाने वाले! अब तू देख लिया गया है, अब फिर तू नया घर नहीं बना सकता। तेरी सारी कड़ियाँ टूट गई हैं और घर का शिखर भी विशृंखलित हो गया है। चित्त पूरी तरह संस्काररहित हो गया है और तृष्णाओं का क्षय प्राप्त हो गया है।",
  "155": "ब्रह्मचर्य का पालन किए बिना अथवा यौवन में धन कमाए बिना, लोग वृद्धावस्था में मत्स्यहीन जलाशय में बूढ़े क्रौंच पक्षी के समान घुट-घुट कर मरते हैं।",
  "156": "ब्रह्मचर्य का पालन किए बिना अथवा यौवन में धन कमाए बिना, लोग वृद्धावस्था में धनुष से छोड़े गए बाण की भाँति पुरानी बातों को याद कर अनुताप करते हुए बिलखते हुए सोते हैं।",
  "chap12": "आत्म",
  "157": "यदि अपने को प्रिय समझते हो तो उसको सुरक्षित रखो। समझदार व्यक्ति जीवन के तीन प्रहरों में से किसी एक में तो अवश्य सचेत हो।",
  "158": "पहले अपने आपको ही उचित कार्य में लगाए, फिर किसी दूसरे को उपदेश करे, तो पंडित क्लेश को प्राप्त नहीं होगा।",
  "159": "यदि पहले अपने को वैसा बनाए जैसा कि दूसरों को उपदेश देता है, तो अपने आपको सुदान्त करने वाला ही दूसरे का दमन कर सकता है।",
  "160": "मनुष्य अपना स्वामी आप है, भला दूसरा कौन स्वामी हो सकता है? अपने आपको भली-भाँति वश में करके ही यह दुर्लभ स्वामित्व प्राप्त होता है।",
  "161": "अपने से पैदा हुआ, अपने से उत्पन्न, अपने द्वारा किया गया पाप कर्म इसे करने वाले दुर्बुद्धि को उसी प्रकार पीड़ित करता है जिस प्रकार कि पाषाणमय मणि को वज्र।",
  "162": "शाल वृक्ष पर फैली हुई मालुवा लता के समान जिसका दुराचार खूब फैला हुआ है, वह अपने आपको वैसा ही बना लेता है जैसा कि उसके शत्रु चाहते हैं।",
  "163": "बुरे और अपने लिए अहितकारी काम करना सहल है, किंतु भला और हितकारी काम करना बड़ा दुष्कर है।",
  "164": "धर्म का जीवन जीने वाले, आर्य, अरहंतों के शासन की जो दुर्बुद्धि पापपूर्ण दृष्टि के कारण निंदा करता है, वह बाँस के फल की भाँति आत्म-विनाश के लिए ही फलता है।",
  "165": "अपने द्वारा किया गया पाप ही अपने को मैला करता है। स्वयं पाप न करे तो आदमी आप ही विशुद्ध बना रहे। शुद्धि-अशुद्धि तो प्रत्येक मनुष्य की अपनी-अपनी ही है। कोई दूसरा भला किसी दूसरे को कैसे शुद्ध कर सकता है?",
  "166": "परार्थ के लिए आत्मार्थ को बहुत ज्यादा भी न छोड़े। आत्मार्थ को जानकर सदर्थ में लगा रहे।",
  "chap13": "लोक",
  "167": "निकृष्ट धर्म का सेवन न करे, न प्रमाद में लिप्त हो। मिथ्यादृष्टि को न अपनाए, और अपने आवागमन को बढ़ाने वाला न बने।",
  "168": "उठे, प्रमाद न करे, सुचरित धर्म का आचरण करे। धर्मचारी इस लोक और परलोक दोनों जगह सुखपूर्वक विहार करता है।",
  "169": "सुचरित धर्म का आचरण करे, दुराचरण से बचे. धर्मचारी इस लोक और परलोक दोनों जगह सुखपूर्वक विहार करता है।",
  "170": "जो इस लोक को बुलबुले के समान और मृग-मरीचिका के समान देखे, उस व्यक्ति की ओर मृत्युराज आँख उठाकर नहीं देखता।",
  "171": "आओ, चित्रित राजरथ के समान इस लोक को देखो जहाँ मूढ़ जन आसक्त होते हैं, ज्ञानवान जन आसक्त नहीं होते।",
  "172": "जो पहले प्रमाद करके भी पीछे प्रमाद नहीं करता, वह मेघमुक्त चंद्रमा की भाँति इस लोक को प्रकाशित करता है।",
  "173": "जो अपने पहले किए हुए पाप कर्म को वर्तमान के कुशलकर्म से ढँक लेता है, वह मेघमुक्त चंद्रमा की भाँति इस लोक को खूब भासमान करता है।",
  "174": "यह लोक अंधे जैसा है, यहाँ विपश्यना करने वाले थोड़े ही हैं। जाल से मुक्त हुए पक्षी की भाँति विरले ही सुगति अथवा निर्वाण को जाते हैं।",
  "175": "हंस सूर्य-पथ में जाते हैं, कोई ऋद्धि-बल से आकाश में जाते हैं। पंडित लोग सेनासहित मार को जीतकर इस लोक से निर्वाण को ले जाए जाते हैं।",
  "176": "एक धर्म (सत्य) का अतिक्रमण कर जो झूठ बोलता है, परलोक के प्रति उदासीन ऐसे प्राणी के लिए कोई इस प्रकार का पाप नहीं रह जाता जो वह न कर सके।",
  "177": "कृपण लोग देवलोक में नहीं जाते हैं, मूढ़ लोग ही दान की प्रशंसा नहीं करते हैं। पंडित व्यक्ति दान का अनुमोदन करता हुआ उसी कर्म के आधार से परलोक में सुखी होता है।",
  "178": "पृथ्वी के एकच्छत्र राज्य, अथवा स्वर्गारोहण, अथवा सारे लोकों के आधिपत्य से अधिक उत्तम है स्रोतापत्ति का फल।",
  "chap14": "बुद्ध",
  "179": "जिसकी विजय को अविजय में नहीं पलटा जा सकता, जिसके द्वारा विजित राग, द्वेष, मोहादि वापस संसार में नहीं आते, उस अपद अनंतगोचर बुद्ध को किस उपाय से मोहित कर सकोगे?",
  "180": "जिसकी जाल फैलाने वाली विषाक्त तृष्णा कहीं भी ले जाने में समर्थ नहीं रही, उस अनंतगोचर बुद्ध को किस उपाय से मोहित कर सकोगे?",
  "181": "जो पंडित जन ध्यान करने में लगे रहते हैं, और त्याग और उपशमन में लगे रहते हैं, उन स्मृतिमान संबुद्धों की देवता भी स्पृहा करते हैं।",
  "182": "मनुष्य योनि प्राप्त होना कठिन है, मनुष्यों का जीवित रहना कठिन है, सद्धर्म का श्रवण कर पाना कठिन है और बुद्धों का उत्पन्न होना कठिन है।",
  "183": "सभी पापकर्मों को न करना, पुण्यकर्मों की संपदा संचित करना, अपने चित्त को परिशुद्ध करनायही बुद्धों की शिक्षा है।",
  "184": "सहनशीलता और क्षमाशीलता परम तप है। बुद्ध निर्वाण को उत्तम बतलाते हैं। दूसरे का घात करने वाला प्रव्रजित नहीं होता और दूसरे को सताने वाला श्रमण नहीं हो सकता।",
  "185": "निंदा न करना, घात न करना, प्रातिमोक्ष द्वारा अपने को सुरक्षित रखना, आहार की मात्रा का जानकार होना, एकांत में सोना-बैठना और चित्त को एकाग्र करने के प्रयत्न में जुटनायह बुद्धों की शिक्षा है।",
  "186": "स्वर्ण मुद्राओं की वर्षा से भी कामभोगों की तृप्ति नहीं हो सकती। यह जानकर कि कामभोग अल्प आस्वाद वाले और दुःखद होते हैं, पंडित",
  "187": "दिव्य कामभोगों में भी आनंद प्राप्त नहीं करता। सम्यक संबुद्ध का श्रावक तृष्णा का क्षय करने में लगा रहता है।",
  "188": "मनुष्य भय के मारे पर्वतों, वनों, उद्यानों, वृक्षों, चैत्यों आदि बहुतों की शरण में जाते हैं,",
  "189": "परंतु यह शरण मंगलकारी नहीं है, यह शरण उत्तम नहीं है। इस शरण को पाकर सभी दुःखों से छुटकारा नहीं होता।",
  "190": "जो बुद्ध, धर्म और संघ की शरण गया है, जो चार आर्य सत्योंदुःख, दुःख की उत्पत्ति, दुःख से मुक्ति और मुक्तिगामी आर्य अष्टांगिक मार्गको सम्यक प्रज्ञा से देखता है,",
  "191": "दुःख, दुःख-समुत्पाद, दुःख का अतिक्रमण और दुःख-उपशम की ओर ले जाने वाले आर्य अष्टांगिक मार्ग को देखता है,",
  "192": "यही मंगलदायक शरण है, यही उत्तम शरण है। इसी शरण को प्राप्त कर व्यक्ति सभी दुःखों से मुक्त होता है।",
  "193": "श्रेष्ठ पुरुष का जन्म दुर्लभ होता है, वह सब जगह पैदा नहीं होता। वह उत्तम प्रज्ञा वाला धीर पुरुष जहाँ उत्पन्न होता है उस कुल में सुख की वृद्धि होती है।",
  "194": "सुखदायी है बुद्धों का उत्पन्न होना, सुखदायी है सद्धर्म का उपदेश। सुखदायी है संघ की एकता, सुखदायी है एक साथ तपना।",
  "195": "पूजा के योग्य बुद्धों अथवा उनके श्रावकोंजो प्रपंच का अतिक्रमण कर चुके हैं और शोक तथा भय को पार कर गए हैं",
  "196": "निर्वाणप्राप्त, निर्भय हुएऐसे लोगों की पूजा के पुण्य का परिमाण इतना होगा, यह नहीं कहा जा सकता।",
  "chap15": "सुख",
  "197": "वेरियों के बीच अवैरी होकर, अहो! हम बड़े सुख से जी रहे हैं। वैरी मनुष्यों के बीच हम अवैरी होकर विचरण करते हैं।",
  "198": "आतुर लोगों के बीच, अहो! हम अनातुर रहकर बड़े सुख से जी रहे हैं। आतुर मनुष्यों में हम अनातुर रहकर विचरण करते हैं।",
  "199": "लोभी लोगों के बीच हम अलोभी होकर, अहो! हम बड़े सुख से जी रहे हैं। लोभी के बीच हम निर्लेभी होकर विचरण करते हैं।",
  "200": "जिनके पास कुछ नहीं है, अहो! वैसे हम कैसे बड़े सुख से जी रहे हैं। आभास्वर देवताओं के समान हम प्रीति का ही भोजन करने वाले होंगे।",
  "201": "विजय वैर को जन्म देती है, पराजित व्यक्ति दुःख की नींद सोता है। जिसके (राग-द्वेषादि) शांत हो गए हैं, वह क्षीणाश्रव जय और पराजय को छोड़कर सुख की नींद सोता है।",
  "202": "राग के समान कोई आग नहीं, द्वेष के समान कोई दुर्भाग्य नहीं, पंचस्कंध (रूप, वेदना, संज्ञा, संस्कार तथा विज्ञान) के समान कोई दुःख नहीं, शांति (निर्वाण) से बढ़कर कोई सुख नहीं।",
  "203": "भूख (तृष्णा) सबसे बड़ा रोग है, संस्कार सबसे बड़ा दुःख। (तृष्णा और उससे बनते संस्कारों को अपने भीतर विपश्यना साधना द्वारा) यथाभूत जानकर जो निर्वाण प्राप्त होता है, वह सबसे बड़ा सुख है।",
  "204": "आरोग्य परम लाभ है, संतुष्टि परम धन है, विश्वास परम बंधु है, निर्वाण परम सुख है।",
  "205": "पूर्ण एकांत का रस-पान कर और वैसे ही शांति (निर्वाण) का रस-पान कर व्यक्ति निडर होता है, और धर्म-प्रीति का रस-पान कर वह निष्पाप हो जाता है।",
  "206": "आर्यों (श्रेष्ठ पुरुषों) का दर्शन अच्छा होता है, संतों के साथ निवास सदा सुखकर होता है। मूढ़ पुरुषों के अदर्शन से सदा सुखी बने रहो।",
  "207": "मूढ़ पुरुषों के साथ संगत करने वाला दीर्घ काल तक शोकग्रस्त रहता है, मूढ़ों का सहवास शत्रु के समान सदा दुःखदायी होता है, बंधुओं के समागम की भाँति ज्ञानियों का सहवास सुखदायी होता है।",
  "208": "इसलिए धीर, प्रज्ञावान, बहुश्रुत, उद्योगी, व्रती, आर्यऐसे सुमेध सत्पुरुष का साहचर्य करे जैसे चंद्रमा नक्षत्र-पथ का करता है।",
  "chap16": "प्रिय",
  "209": "अनुचित कर्म (अयोनिसोमनसिकार) में लगा हुआ, उचित कर्म (योनिसोमनसिकार) में न लगने वाला और सदर्थ को छोड़कर (पाँच कामगुणरूपी) प्रिय को पकड़ने वाला, उस पुरुष की स्पृहा करे जो आत्मोन्नति में लगा हो।",
  "210": "प्रियों (सत्त्वों अथवा संस्कारों) का संग न करे और न कभी अप्रियों का ही। प्रियों का अदर्शन दुःखदायी होता है और अप्रियों का दर्शन भी दुःखदायी होता है।",
  "211": "इसलिए किसी को प्रिय न बनाएँ, क्योंकि प्रिय का वियोग बुरा लगता है। जिनके कोई प्रिय-अप्रिय नहीं होते, उनके कोई बंधन नहीं होते।",
  "212": "प्रिय वस्तु से शोक उत्पन्न होता है, प्रिय से भय उत्पन्न होता है। प्रिय के बंधन से विमुक्त व्यक्ति को शोक नहीं होता, फिर भय कहाँ से होगा?",
  "213": "प्रेम करने से शोक उत्पन्न होता है, प्रेम से भय उत्पन्न होता है। प्रेम के बंधन से विमुक्त व्यक्ति को शोक नहीं होता, फिर भय कहाँ से होगा?",
  "214": "(पंचकामगुणात्मक) राग करने से शोक उत्पन्न होता है, राग से भय उत्पन्न होता है। राग के बंधन से विमुक्त व्यक्ति को शोक नहीं होता, फिर भय कहाँ से होगा?",
  "215": "काम (कामना) से शोक उत्पन्न होता है, काम से भय उत्पन्न होता है। काम से विमुक्त व्यक्ति को शोक नहीं होता, फिर भय कहाँ से होगा?",
  "216": "(छह द्वारों पर होने वाली) तृष्णा से शोक उत्पन्न होता है, तृष्णा से भय उत्पन्न होता है। तृष्णा से विमुक्त व्यक्ति को शोक नहीं होता, फिर भय कहाँ से होगा?",
  "217": "जो शीलसंपन्न, सम्यक दृष्टिसंपन्न, धर्मनिष्ठ (नौ प्रकार के लोकोत्तर धर्मों में स्थित), सत्यवादी, कर्तव्यपरायण है, उसे लोग प्यार करते हैं।",
  "218": "जो अनाख्यात (अवर्णनीय, निर्वाण) का अभिलाषी हो, उसी में जिसका मन लगा हो, और (अनागामी मार्ग में होने से) कामभोगों में जिसका चित्त न रुधा हो, वह ऊर्ध्वस्रोत कहा जाता है।",
  "219": "जैसे चिरकाल तक परदेस में रहने के बाद दूर देश से सकुशल घर आए पुरुष का संबंधी, मित्र और हितैषीजन स्वागत करते हैं;",
  "220": "वैसे ही पुण्यकर्मा पुरुष के इस लोक से परलोक में जाने पर उसके पुण्य उसका वैसे ही स्वागत करते हैं जैसे अपने प्रिय के लौटने पर उसके संबंधी उसका स्वागत करते हैं।",
  "chap17": "क्रोध",
  "221": "क्रोध को छोड़ दे, अभिमान का त्याग करे, सारे संयोजनों (बंधनों) को पार कर जाए। ऐसे नामरूप में आसक्त न होने वाले अपरिग्रही को दुःख संतप्त नहीं करते।",
  "222": "जो भड़के हुए क्रोध को (बड़े वेग से) घूमते हुए रथ के समान रोक ले, उसे मैं सारथि कहता हूँ, दूसरे लोग तो मात्र लगाम पकड़ने वाले होते हैं।",
  "223": "अक्रोध से क्रोध को जीते, अभद्र को भद्र बनकर जीते, कृपण को दान से जीते और झूठ बोलने वाले को सत्य से जीते।",
  "224": "सच बोले, क्रोध न करे, माँगने पर थोड़ा रहते भी दे। इन तीन कारणों से कोई व्यक्ति देवताओं के निकट (अर्थात देवलोक में) चला जाता है।",
  "225": "जो मुनि जन अहिंसक हैं और जो सदा काया में संयत रहते हैं, वे उस अच्युत स्थान (निर्वाण) को पा लेते हैं जहाँ पहुँचकर शोक नहीं करते।",
  "226": "जो सदा जागरूक रहते हैं, रात-दिन सीखने में लगे रहते हैं और जिनका ध्येय निर्वाण प्राप्त करना है, उनके आश्रव नष्ट हो जाते हैं।",
  "227": "हे अतुल! यह पुरानी बात है, आज की नहींलोग चुप बैठे हुए की निंदा करते हैं, बहुत बोलने वाले की निंदा करते हैं, मितभाषी की भी निंदा करते हैं। संसार में अनिंदित कोई नहीं है।",
  "228": "ऐसा पुरुष जिसकी निंदा ही निंदा होती हो, या प्रशंसा ही प्रशंसा, न कभी था, न होगा, न इस समय है।",
  "229": "विज्ञ लोग सोच-विचारकर जिस प्रज्ञा व शील से युक्त, निर्दोष, मेधावी की दिन-प्रतिदिन प्रशंसा करते हैं",
  "230": "जम्बोनद सोने की अशर्फी के समान उसकी कौन निंदा कर सकता है? देवता भी उसकी प्रशंसा करते हैं, वह ब्रह्मा द्वारा भी प्रशंसित होता है।",
  "231": "कायिक चंचलता से बचा रहे, काय से संयत रहे। कायिक दुराचार को त्यागकर शरीर से सदाचरण करे।",
  "232": "वाचिक चंचलता से बचा रहे, वाणी से संयत रहे। वाचिक दुराचार को त्यागकर वाणी का सदाचरण करे।",
  "233": "मानसिक चंचलता से बचे, मन से संयत रहे (उसे संयमित रखे)। मानसिक दुराचार को त्यागकर मानसिक सदाचरण करे।",
  "234": "जो धीर पुरुष काय से संयत हैं, वाणी से संयत हैं, मन से संयत हैं, वे ही पूर्णतया संयत हैं।",
  "chap18": "मल",
  "235": "पीले पत्ते के समान इस समय तू है, यमदूत तेरे पास खड़े हैं, तू प्रयाण के लिए तैयार है और (कुशलकर्मों का) पाथेय तेरे पास कुछ नहीं है।",
  "236": "सो तू अपने लिए द्वीप (रक्षास्थल) बना, शीघ्र ही (साधना का) अभ्यास कर पंडित हो जा। तू मल का प्रक्षालन कर, निर्मल बन, दिव्य आर्यभूमि को पा लेगा।",
  "237": "अब तेरी आयु समाप्त हो चुकी है, तू यम के निकट पहुँच गया है, बीच में तेरा कोई ठिकाना भी नहीं है और न ही तेरे पास कोई पाथेय है।",
  "238": "सो तू अपने लिए द्वीप बना, शीघ्र ही (साधना का) अभ्यास कर पंडित हो जा। तू मल का प्रक्षालन कर, निर्मल बन, पुनः जन्म, जरा, रोग तथा मृत्यु के बंधन में नहीं पड़ेगा।",
  "239": "समझदार व्यक्ति को चाहिए कि वह अपने मैल को क्रमशः थोड़ा-थोड़ा, क्षण-प्रतिक्षण वैसे ही दूर करे जैसे कि रजतकार (सुनार) चाँदी के मैल को दूर करता है।",
  "240": "जैसे लोहे के ऊपर उठा हुआ मल (जंग) उसी पर उठकर उसी को खाता है, वैसे ही मर्यादा का उल्लंघन करने वाले व्यक्ति के अपने ही कर्म उसे दुर्गति की ओर ले जाते हैं।",
  "241": "स्वाध्याय न करना परियत्ति का मल है, मरम्मत न करना घरों का मल है, आलस्य सौंदर्य का मल है और प्रमाद प्रहरी का मल है।",
  "242": "दुश्चरित्र होना स्त्री का मल है, कृपणता दाता का मल है और सभी पापपूर्ण अकुशल धर्म इहलोक और परलोक के मल हैं।",
  "243": "उससे भी बढ़कर अविद्या परम मल है। हे साधको! इस मल को दूर करके निर्मल बन जाओ।",
  "244": "निर्लज्ज, कौवे के समान शूर, विनाशी, आत्मश्लाघी, दुःसाहसी, मलिन पुरुष का जीवन सुखपूर्वक बीतता हुआ देखा जाता है।",
  "245": "लजालु, नित्य पवित्रता का ध्यान रखने वाले, अप्रमादी, शुद्ध जीविका वाले पुरुष के जीवन को कठिनाई से बीतते देखा जाता है।",
  "246": "जो संसार में हिंसा करता है, झूठ बोलता है, चोरी करता है, परस्त्रीगमन करता है,",
  "247": "मद्यपान करता है, वह व्यक्ति यहींइसी लोक मेंअपनी जड़ खोदता है।",
  "248": "हे पुरुष! ऐसा जान कि अकुशल धर्म पर संयम करना आसान नहीं है। तुझे लोभ तथा अकुशल धर्म चिरकाल तक दुःख में न राँधते रहें।",
  "249": "लोग अपनी श्रद्धा और प्रसन्नता के अनुरूप दान देते हैं। दूसरों के खाने-पीने से जो खिन्न होता है, वह दिन हो या रात कभी भी समाधि को प्राप्त नहीं करता है।",
  "250": "किंतु जिसकी ऐसी मनोवृत्ति उच्छिन्न हो गई है, वही दिन हो या रात सदैव एकाग्रता को प्राप्त होता है।",
  "251": "राग के समान अग्नि नहीं है, न द्वेष के समान जकड़न। मोह के समान फंदा नहीं है, न तृष्णा के समान नदी।",
  "252": "दूसरों का दोष देखना आसान है, किंतु अपना दोष देखना कठिन। वह दूसरों के दोषों को भूसे की तरह उड़ाता फिरता है, किंतु अपने दोषों को वैसे ही ढँकता है जैसे बेईमान जुआरी पासे को।",
  "253": "दूसरों के दोषों को देखने में लगे हुए, सदा शिकायत करने की चेतना वाले व्यक्ति के आश्रव बढ़ते हैं। वह आश्रवों के क्षय से दूर होता है।",
  "254": "आकाश में कोई पद नहीं होता, (बुद्ध-शासन से) बाहर कोई श्रमण नहीं होता। लोग भाँति-भाँति के प्रपंचों में पड़े रहते हैं, किंतु तथागत निष्प्रपंच होते हैं।",
  "255": "आकाश में कोई पद नहीं होता, (बुद्ध-शासन से) बाहर कोई श्रमण नहीं होता, संस्कार (पाँच स्कंध) शाश्वत नहीं होते, बुद्धों में किसी प्रकार की चंचलता नहीं होती।",
  "chap19": "धम्मस्थ",
  "256": "जो व्यक्ति सहसा किसी बात का निश्चय कर ले, वह धर्मिष्ठ नहीं कहा जाता। जो अर्थ और अनर्थ दोनों का चिंतन कर निश्चय करे, वह पंडित कहलाता है।",
  "257": "जो व्यक्ति धीरज के साथ, धर्मपूर्वक, निष्पक्ष होकर दूसरों का मार्गदर्शन करता है, वह धर्मरक्षक मेधावी 'धर्मिष्ठ' कहा जाता है।",
  "258": "बहुत बोलने से कोई पंडित नहीं हो जाता। कुशल-क्षेम से रहने वाला, वैर-रहित तथा निर्भय व्यक्ति ही 'पंडित' कहा जाता है।",
  "259": "बहुत बोलने से कोई धर्मधर नहीं हो जाता। जो कोई थोड़ी सी भी बात सुनकर काय से धर्म का दर्शन करने लगता है और जो धर्म के आचरण में प्रमाद नहीं करता, वही निःसंदेह 'धर्मधर' होता है।",
  "260": "सिर के बाल पकने से कोई स्थविर नहीं हो जाता, केवल उसकी आयु पकी है, वह तो 'मोघजीर्ण' कहा जाता है।",
  "261": "जिसमें सत्य, धर्म, अहिंसा, संयम और दम है, वही विगतमल, धृतिसंपन्न स्थविर कहा जाता है।",
  "262": "जो ईर्ष्यालु, मत्सरी और शठ है, वह वक्तृमात्र होने से अथवा सुंदर-रूप होने से 'साधुरूप' मनुष्य नहीं हो जाता.",
  "263": "जिसके भीतर से ये जड़मूल से सर्वथा उच्छिन्न हो गए हैं, वह विगतदोष मेधावी पुरुष 'साधुरूप' कहा जाता है।",
  "264": "जो अब्रती है और जो झूठ बोलने वाला है, वह सिर मुँड़ा लेने मात्र से श्रमण नहीं हो जाता। इच्छा और लोभ से ग्रस्त भला क्या श्रमण होगा?",
  "265": "जो छोटे-बड़े पापों का सर्वशः शमन कर लेता है, पापों के शमित होने के कारण वह 'श्रमण' कहा जाता है।",
  "266": "दूसरों से भिक्षा माँगने मात्र से कोई भिक्षु नहीं हो जाता, और न ही भिक्षु होता है विषम धर्म को ग्रहण करने से।",
  "267": "जो यहाँ पुण्य और पाप को दूर रखकर, ब्रह्मचारी बन, विचार करके लोक में विचरण करता है, वही वस्तुतः 'भिक्षु' कहा जाता है।",
  "268": "अविद्वान और मूढ़-समान पुरुष केवल मौन रहने से मुनि नहीं हो जाता। जो पंडित तराजू के समान तौलकर उत्तम तत्त्व को ग्रहण कर",
  "269": "पाप कर्मों का परित्याग कर देता है, वह मुनि होता है। चूँकि वह दोनों लोकों का मनन करता है, इस कारण वह 'मुनि' कहा जाता है।",
  "270": "प्राणियों की हिंसा करने से कोई आर्य नहीं हो जाता। सभी प्राणियों की हिंसा न करने से वह 'आर्य' कहा जाता है।",
  "271": "केवल शील और व्रत से, या बहुश्रुत होने से, या समाधि के लाभ से, या एकांतवासी होने से",
  "272": "'पृथग्जन जिसे सेवन नहीं कर सकते मैंने उस नैष्क्रम्य-सुख को प्राप्त कर लिया है'ऐसा सोच हे भिक्षुओ! आश्रवों का क्षय न हो जाने तक तुम आश्वस्त होकर मत बैठे रहो।",
  "chap20": "मार्ग",
  "273": "मार्गों में अष्टांगिक मार्ग श्रेष्ठ है, सच्चाइयों में चार आर्य-सत्य, धर्मों में वीतरागता श्रेष्ठ है, द्विपदों में चक्षुमान बुद्ध।",
  "274": "दर्शन की विशुद्धि के लिए यही मार्ग है, कोई दूसरा नहीं। तुम इसी पर आरूढ़ होओ, यह मार को किकर्तव्यविमूढ़ बनाने वाला है।",
  "275": "इस मार्ग पर आरूढ़ होकर तुम दुःख का अंत कर लोगे। मेरे द्वारा शल्य काटने वाले इस मार्ग को स्वयं जानकर तुम्हारे लिए आख्यान किया गया है।",
  "276": "तपना तो तुम्हें ही पड़ेगा, तथागत तो मार्ग आख्यात करते हैं। इस मार्ग पर आरूढ़ होकर ध्यान करने वाले मार के बंधन से सर्वथा मुक्त हो जाते हैं।",
  "277": "'सारे संस्कार अनित्य हैं'। इस सच्चाई को जब कोई प्रज्ञा से देख लेता है, तब उसको दुःखों से निर्वेद प्राप्त होता हैऐसा है यह विशुद्धि का मार्ग!",
  "278": "'सारे संस्कार दुःख हैं'। इस सच्चाई को जब कोई प्रज्ञा से देख लेता है, तब उसको सभी दुःखों से निर्वेद प्राप्त होता हैऐसा है यह विशुद्धि का मार्ग!",
  "279": "'सभी धर्म अनात्म हैं'। इस सच्चाई को जब कोई प्रज्ञा से देख लेता है, तब उसको सभी दुःखों से निर्वेद प्राप्त होता हैऐसा है यह विशुद्धि का मार्ग!",
  "280": "जो उद्योग करने के समय उद्योग नहीं करता, युवा और बलशाली होने पर भी आलस्य करता है, संकल्पों को गिरा देता है, निर्वीर्य होता हैऐसा आलसी व्यक्ति प्रज्ञा का मार्ग नहीं पा सकता।",
  "281": "वाणी को संयत रखे, मन को संयत रखे और शरीर से कोई अकुशल काम न करे। इन तीनों कर्मपथों का विशोधन करे। बुद्ध के बताए मार्ग का अनुसरण करे।",
  "282": "योग से प्रज्ञा उत्पन्न होती है, उसके अभाव से उसका क्षय होता है। उत्पत्ति और विनाश के दो प्रकार के मार्गों को जानकर अपने आप को इस प्रकार विनियोजित करे जिससे प्रज्ञा की भरपूर वृद्धि हो।",
  "283": "वन (आसक्ति) को काटो, वृक्ष को नहीं। भय वन से पैदा होता है। हे साधको! वन को और झाड़ को काटकर अनासक्त हो जाओ।",
  "284": "जब तक अणुमात्र भी नर की नारियों के प्रति कामना बनी रहती है, तब तक जैसे दूध पीने वाला बछड़ा माता में आबद्ध रहता है वैसे ही वह नर भी उनमें आसक्त रहता है।",
  "285": "जिस प्रकार हाथ से शरद ऋतु के कुमुद को तोड़ा जाता है, उसी प्रकार अपने स्नेह को उच्छिन्न कर डालो। सुगत द्वारा उपदिष्ट इस शांतिमार्ग निर्वाण को ही भावित करो।",
  "286": "'मैं यहाँ वर्षाकाल में रहूँगा, यहाँ हेमंत और ग्रीष्म में'मूढ़ व्यक्ति इस प्रकार सोचता है और किसी संभावित बाधा को नहीं बूझता।",
  "287": "जैसे सोए हुए गाँव को कोई बड़ी बाढ़ बहाकर ले जाए, वैसे ही पुत्र और पशु के नशे में धुत्त आसक्तचित्त व्यक्ति को मृत्यु ले जाती है।",
  "288": "पुत्र रक्षा नहीं कर सकते, न पिता और न ही बंधुजन। जब मृत्यु पकड़ लेती है तब जाति वाले रक्षा नहीं कर सकते।",
  "289": "इस तथ्य को जानकर शील में संयत पंडित निर्वाण की ओर ले जाने वाले मार्ग का शीघ्र ही विशोधन करे।",
  "chap21": "प्रकीर्णक",
  "290": "यदि कोई धीर व्यक्ति थोड़े से सुख के परित्याग से विपुल सुख का लाभ देखे, तो वह विपुल सुख का ख्याल करके थोड़े से सुख को छोड़ दे।",
  "291": "दूसरे को दुःख देकर जो अपने लिए सुख चाहता है, वैर के संसर्ग में पड़कर वह वैर से मुक्त नहीं हो पाता।",
  "292": "जो करणीय से हाथ खींच ले किंतु अकरणीय को करे, ऐसे खोखले प्रमादियों के आश्रव बढ़ते हैं।",
  "293": "जिनकी कायानुस्मृति नित्य उपस्थित रहती है, वे कभी कोई अकरणीय कर्म नहीं करते, सदा करणीय ही करते हैं। ऐसे स्मृतिमान और प्रज्ञावान साधकों के आश्रव क्षय को प्राप्त होते हैं।",
  "294": "माता (तृष्णा), पिता (अहंकार), दो क्षत्रिय राजाओं, अनुचर सहित राष्ट्र का हनन कर ब्राह्मण दुःखरहित हो जाता है।",
  "295": "माता (तृष्णा), पिता (अहंकार), दो श्रोत्रिय राजाओं और पाँच व्याघ्रों में पाँचवें (संदेह) का हनन कर ब्राह्मण दुःखरहित हो जाता है।",
  "296": "जिनकी दिन-रात बुद्ध-विषयक स्मृति बनी रहती है, वे गौतम के श्रावक सदैव भली-भाँति प्रबुद्ध बने रहते हैं।",
  "297": "जिनकी दिन-रात धर्म-विषयक स्मृति बनी रहती है, वे गौतम के श्रावक सदैव भली-भाँति प्रबुद्ध बने रहते हैं।",
  "298": "जिनकी दिन-रात संघ-विषयक स्मृति बनी रहती है, वे गौतम के श्रावक सदैव भली-भाँति प्रबुद्ध बने रहते हैं।",
  "299": "जिनमें दिन-रात कायगता स्मृति की निरंतरता बनी रहती है, गौतम के वे श्रावक सदैव भली-भाँति प्रबुद्ध बने रहते हैं।",
  "300": "जिनका मन दिन-रात अहिंसा में रमा रहता है, वे गौतम के श्रावक सदैव भली-भाँति प्रबुद्ध बने रहते हैं।",
  "301": "जिनका मन दिन-रात मैत्री-भावना में रत रहता है, वे गौतम के श्रावक सदैव भली-भाँति प्रबुद्ध बने रहते हैं।",
  "302": "कष्टपूर्ण प्रव्रज्या में रत रहना दुष्कर होता है, अनुपयुक्त घर दुःखद होते हैं, असमान व्यक्ति से सहवास दुःखदायी होता है और संसार-मार्ग का पथिक होना दुःखपूर्ण होता है। इसलिए न तो संसार-मार्ग का पथिक बनें और न ही दुःख में पड़ने वाले बनें।",
  "303": "जो श्रद्धावान, शीलवान, यश और भोग से युक्त है, वह जिस-जिस प्रदेश में जाता है, वहीं-वहीं पूजित होता है।",
  "304": "सत्पुरुष हिमालय पर्वत के समान दूर से ही प्रकाशमान होते हैं, किंतु असंत यहीं पास में होने पर भी रात में फेंके गए बाण की भाँति दिखाई नहीं देते।",
  "305": "एकाकी आसन, एकाकी शय्या और तन्द्रा रहित होकर अकेले विचरण करने वाला, अपने को दमन कर अकेला ही वनांत में रमण करे।",
  "chap22": "निरय",
  "306": "असत्य बोलने वाला नरक में जाता है और वह भी जो पापकर्म करके कहता है कि 'मैंने नहीं किया'। नीच कर्म करने वाले ये दोनों ही प्रकार के मनुष्य मरकर परलोक में एक-समान हो जाते हैं।",
  "307": "कंठ में काषाय वस्त्र डाले कितने ही पापी असंयमी हैं, जो अपने पापकर्मों के कारण नरक में उत्पन्न होते हैं।",
  "308": "असंयमी और दुराचारी होकर राष्ट्र का अन्न खाने की अपेक्षा अग्नि-शिखा के समान तप्त लोहे के गोले को खाना अधिक अच्छा है।",
  "309": "प्रमादी परस्त्रीगामी की चार गतियाँ होती हैं: (१) अपुण्य-लाभ, (२) सुख की नींद न आना, (३) निंदा और (४) नरक।",
  "310": "अपुण्य-लाभ, बुरी गति, भयभीत पुरुष का भयभीत स्त्री के साथ अल्प सुख और राजा का भारी दंडइसलिए पुरुष परस्त्रीगमन न करे।",
  "311": "जैसे गलत ढंग से पकड़ा गया कुश (घास) हाथ को ही घायल कर देता है, वैसे ही गलत प्रकार से ग्रहण किया गया श्रामण्य नरक की ओर खींच ले जाता है।",
  "312": "जो कर्म शिथिलता से किया जाए, जो व्रत मलिन है और जो ब्रह्मचर्य अशुद्ध है, वह महान फल देने वाला नहीं होता।",
  "313": "यदि कोई कार्य करना हो तो उसे दृढ़ पराक्रम के साथ करे। शिथिल परिव्राजक अपने भीतर और भी अधिक मल बिखेरता है।",
  "314": "बुरे काम का न करना ही श्रेयस्कर है क्योंकि दुष्कृत करने वाला पीछे पछताता है; और अच्छे काम का करना श्रेयस्कर है जिसे करके पीछे पछताना नहीं पड़ता।",
  "315": "जैसे सीमावर्ती नगर भीतर-बाहर से सुरक्षित होता है, वैसे ही अपने आपको रक्षित रखें। क्षण भर के लिए भी असावधान न हों, क्योंकि अवसर चूकने वाले नरक में पड़कर शोक करते हैं।",
  "316": "जो निर्लज्जता के कार्यों में लज्जा करते हैं और लज्जाजनक कार्यों में लज्जा नहीं करते, ऐसी मिथ्या दृष्टि वाले प्राणी दुर्गति को प्राप्त होते हैं।",
  "317": "भयरहित कर्म में भय देखने वाले और भयानक कार्यों में भय न देखने वाले, मिथ्या दृष्टि से ग्रस्त प्राणी दुर्गति को प्राप्त होते हैं।",
  "318": "निर्दोष में दोष देखने वाले और दोष में निर्दोष की दृष्टि रखने वाले, मिथ्या दृष्टि से ग्रस्त प्राणी दुर्गति को प्राप्त होते हैं।",
  "319": "दोष को दोष और निर्दोष को निर्दोष जानकर सम्यक दृष्टि वाले प्राणी सुगति को प्राप्त होते हैं।",
  "chap23": "नाग",
  "320": "जैसे संग्राम में हाथी धनुष से छोड़े गए बाण को सहता है, वैसे ही मैं दूसरों के कटुवचन सहन करूँगा, क्योंकि संसार में दुःशील व्यक्ति ही अधिक हैं।",
  "321": "शिक्षित हाथी को सभा में ले जाते हैं और उसी पर राजा चढ़ता है। मनुष्यों में भी वही श्रेष्ठ है जिसने स्वयं को साध लिया है और जो कटुवचन सह लेता है।",
  "322": "शिक्षित होने पर खच्चर, उत्तम नस्ल के घोड़े और महानाग हाथी उत्तम होते हैं, परंतु स्वयं को वश में करने वाला पुरुष उनसे भी श्रेष्ठ है।",
  "323": "इन सवारियों से उस अगम्य दिशा (निर्वाण) तक नहीं पहुँचा जा सकता, जहाँ संयमित व्यक्ति अपनी सधी हुई इंद्रियों के द्वारा स्वयं पहुँच जाता है।",
  "324": "मदमाता 'धनपाल' नामक हाथी बँध जाने पर भोजन नहीं करता, वह (अपने घर) हाथियों के जंगल का ही स्मरण करता रहता है।",
  "325": "जो आलसी, पेटू, निद्रालु और दाना खाकर पुष्ट हुए मोटे सूअर की तरह करवटें बदल-बदल कर सोता रहता है, वह मंदबुद्धि बार-बार जन्म के चक्र में पड़ता है।",
  "326": "यह चित्त जो पहले जहाँ चाहता था वहाँ भटक जाता था, अब मैं इसे वैसे ही पूरी तरह वश में करूँगा जैसे अंकुशधारी महावत हाथी को करता है।",
  "327": "सजगता में लगो और अपने चित्त की रक्षा करो। दलदल में फँसे हाथी के समान अपने आपको दुःख के दुर्गम मार्ग से बाहर निकालो।",
  "328": "यदि साथ चलने के लिए कोई धैर्यवान और बुद्धिमान साथी मिल जाए, तो सारी बाधाओं को पार करते हुए उसके साथ प्रसन्नतापूर्वक और सचेत होकर विचरण करें।",
  "329": "यदि साथ चलने के लिए कोई योग्य साथी न मिले, तो पराजित राज्य को छोड़कर जाते हुए राजा के समान या जंगल में हाथी के समान अकेले विचरण करें।",
  "330": "अकेला चलना श्रेष्ठ है, किंतु मूर्ख की मित्रता अच्छी नहीं। जंगल के हाथी की भाँति निष्पाप और अनासक्त होकर अकेले विचरण करें।",
  "331": "आवश्यकता पड़ने पर मित्र का होना, जो प्राप्त है उसमें संतुष्ट होना, जीवन के अंत में पुण्य का होना और समस्त दुःखों का क्षय हो जानाये सभी सुखकर हैं।",
  "332": "संसार में माता की सेवा सुखकर है और पिता की सेवा भी। इसी प्रकार श्रमणों और ऋषियों का आदर करना भी सुख का कारण है।",
  "333": "वृद्धावस्था तक शील का पालन करना, अडिग श्रद्धा रखना, प्रज्ञा का लाभ होना और पाप कर्मों से दूर रहनाये सभी सुखदायी हैं।",
  "chap24": "तृष्णा",
  "334": "प्रमादी मनुष्य की तृष्णा लता की भाँति बढ़ती है। वह फल की इच्छा से एक शाखा छोड़ दूसरी पकड़ते बंदर की तरह एक जन्म से दूसरे जन्म में भटकता रहता है।",
  "335": "संसार में यह विषैली तृष्णा जिसे दबा लेती है, उसके शोक वैसे ही बढ़ते हैं जैसे वर्षा ऋतु में जंगली घास बढ़ती है।",
  "336": "किंतु जो इस कठिन तृष्णा पर विजय पा लेता है, उसके शोक वैसे ही झड़ जाते हैं जैसे कमल के पत्ते से पानी की बूँद।",
  "337": "इसलिए मैं तुम्हारा कल्याण चाहता हूँ: जैसे खस के लिए घास को जड़ से खोदते हैं, वैसे ही तृष्णा को जड़ से उखाड़ डालो, ताकि मार तुम्हें बार-बार नष्ट न कर सके।",
  "338": "जैसे जड़ के सुरक्षित रहने पर कटा हुआ वृक्ष फिर उग आता है, वैसे ही तृष्णा के समूल नष्ट न होने पर दुःख बार-बार उत्पन्न होता है।",
  "339": "जिसकी इंद्रियों के छत्तीस स्रोत विषय-भोगों की ओर बहते हैं, उस मिथ्या दृष्टि वाले व्यक्ति को उसके रागात्मक संकल्प बहा ले जाते हैं।",
  "340": "तृष्णा की ये धाराएँ सर्वत्र बहती हैं और इसकी लताएँ हर जगह फैलती हैं। इस लता को उगते देखकर प्रज्ञा की कुल्हाड़ी से इसकी जड़ काट डालो।",
  "341": "प्राणियों को प्रिय लगने वाली ये सुख-धाराएँ ही उन्हें जन्म, जरा और मृत्यु के चक्र में फँसाए रखती हैं।",
  "342": "तृष्णा से घिरे लोग जाल में फँसे खरगोश की भाँति इधर-उधर भागते हैं। बंधनों में जकड़े हुए वे लंबे समय तक बार-बार दुःख भोगते हैं।",
  "343": "तृष्णा से ग्रस्त प्राणी जाल में फँसे खरगोश की तरह तड़पते हैं। इसलिए मुक्ति की इच्छा रखने वाला साधक तृष्णा को दूर करे।",
  "344": "जो संसार के बंधनों से छूटकर फिर उन्हीं की ओर दौड़ता है, वह उस मुक्त व्यक्ति के समान है जो स्वयं वापस बेड़ियों में खिंचा चला आता है।",
  "345": "लोहे, लकड़ी या रस्सी के बंधनों को विद्वान दृढ़ नहीं कहते; असली बंधन तो गहनों, पुत्रों और स्त्रियों के प्रति होने वाली आसक्ति है।",
  "346": "बुद्धिमान इसी को सबसे मजबूत और दुस्त्याज्य बंधन कहते हैं। वे इसी मोह को काटकर, सुखों की अपेक्षा त्यागकर प्रव्रजित हो जाते हैं।",
  "347": "जैसे मकड़ी अपने ही बुने जाल में फँस जाती है, वैसे ही रागी पुरुष अपनी ही तृष्णा के जाल में गिर जाते हैं। धीर पुरुष इस मोह को काटकर बिना किसी चाह के आगे बढ़ जाते हैं।",
  "348": "भूत, भविष्य और वर्तमान की आसक्तियों को छोड़ दो और भव-सागर के पार हो जाओ। सब ओर से मुक्त चित्त होकर तुम फिर जन्म-मृत्यु के चक्र में नहीं पड़ोगे।",
  "349": "जो चंचल चित्त वाला है और केवल सुख ही खोजता है, उसकी तृष्णा और भी बढ़ती है। वह अपने लिए और भी मजबूत बेड़ियाँ तैयार करता है।",
  "350": "जो अपने विचारों को शांत करता है और सदैव सचेत रहकर अशुभ की भावना करता है, वही मार के बंधन को काटकर तृष्णा का विनाश कर पाता है।",
  "351": "जिसने लक्ष्य प्राप्त कर लिया है, जो निर्भय, निष्पाप और तृष्णारहित है, जिसने संसार के काँटों को काट दिया है, उसका यह अंतिम जन्म है।",
  "352": "जो तृष्णारहित, अपरिग्रही और शब्दों के सही अर्थ व क्रम का ज्ञाता है, वही महाप्राज्ञ महापुरुष अपना अंतिम शरीर धारण किए हुए है।",
  "353": "मैं सर्वविजेता, सर्वज्ञ और समस्त विकारों से मुक्त हूँ। तृष्णा के क्षय से पूर्णतः विमुक्त होकर, जब मैंने सब स्वयं ही जान लिया है, तो मैं किसे अपना गुरु बताऊँ?",
  "354": "धर्म का दान सर्वश्रेष्ठ दान है। धर्म का रस सर्वश्रेष्ठ रस है। धर्म का आनंद सर्वश्रेष्ठ आनंद है और तृष्णा का क्षय समस्त दुःखों का अंत है।",
  "355": "भोग-विलास उस मूर्ख को नष्ट कर देते हैं जो मुक्ति का प्रयत्न नहीं करता। धन की तृष्णा में पड़कर वह अपना ही अहित कर बैठता है।",
  "356": "जैसे घास खेतों को नष्ट कर देती है, वैसे ही राग मनुष्य को। इसलिए वीतरागियों को दिया गया दान महान फल देता है।",
  "357": "जैसे घास खेतों को बिगाड़ती है, वैसे ही द्वेष मनुष्य को। इसलिए द्वेषरहित व्यक्तियों को दिया गया दान महान फलदायी होता है।",
  "358": "जैसे घास खेतों का दोष है, वैसे ही मोह मनुष्य का। इसलिए मोहरहित व्यक्तियों को दिया गया दान ही श्रेष्ठ फल देता है।",
  "359": "जैसे घास खेतों को दूषित करती है, वैसे ही इच्छा और तृष्णा मनुष्य को। अतः इच्छारहित और तृष्णारहित सत्पुरुषों को दान देना ही महान फल का कारण है।",
  "chap25": "भिक्षु",
  "360": "आँखों और कानों पर संयम रखना अच्छा है। नाक और जीभ पर नियंत्रण रखना भी श्रेष्ठ है।",
  "361": "शरीर, वाणी और मन का संयम उत्तम है। जो साधक सभी इंद्रियों पर नियंत्रण पा लेता है, वह समस्त दुःखों से मुक्त हो जाता है।",
  "362": "जिसके हाथ, पैर और वाणी सधे हुए हैं, जो भीतर से शांत, एकाकी और संतुष्ट है, उसे ही वास्तव में 'भिक्षु' कहते हैं।",
  "363": "जो भिक्षु अपनी वाणी पर संयम रखता है, सोच-विचारकर बोलता है और धर्म को स्पष्ट करता है, उसका वचन मधुर और कल्याणकारी होता है।",
  "364": "जो धर्म में ही आनंद लेता है और उसी का निरंतर चिंतन व पालन करता है, वह साधक कभी सत्य के मार्ग से नहीं भटकता।",
  "365": "जो अपने पास है उसकी अवहेलना न करें और दूसरों के लाभ की ईर्ष्या न करें। दूसरों से जलने वाला भिक्षु कभी मानसिक शांति प्राप्त नहीं कर पाता।",
  "366": "भले ही लाभ थोड़ा हो, पर जो भिक्षु उससे संतुष्ट रहता है और आलस्य रहित शुद्ध जीवन जीता है, उसकी प्रशंसा देवता भी करते हैं।",
  "367": "जिसके मन में शरीर और नाम के प्रति 'मैं' और 'मेरा' का भाव नहीं है और जो न मिलने पर दुखी नहीं होता, वही सच्चा भिक्षु है।",
  "368": "मैत्री-भाव से रहने वाला जो भिक्षु बुद्ध के मार्ग पर चलता है, वह शांति और निर्वाण के सुखमय पद को प्राप्त करता है।",
  "369": "हे भिक्षु! इस शरीर-रूपी नाव से मोह का पानी बाहर निकाल दो। जब यह नाव हल्की हो जाएगी और तुम राग-द्वेष को काट दोगे, तब निर्वाण प्राप्त कर लोगे।",
  "370": "पाँच बंधनों को काटो, पाँच को छोड़ो और पाँच इंद्रियों को जगाओ। जो इन पाँच आसक्तियों से पार पा लेता है, वही भव-सागर को पार करने वाला कहलाता है।",
  "371": "हे भिक्षु! ध्यान करो, प्रमाद न करो। तुम्हारा मन विषयों में न भटके। कहीं ऐसा न हो कि तुम्हें जलते हुए लोहे के गोले निगलने पड़ें और बाद में पछताना पड़े।",
  "372": "बिना ध्यान के प्रज्ञा नहीं आती और बिना प्रज्ञा के ध्यान नहीं होता। जिसके पास ध्यान और प्रज्ञा दोनों हैं, वह निर्वाण के अत्यंत निकट है।",
  "373": "एकांत में प्रवेश कर जब शांत चित्त साधक सत्य का अनुभव करता है, तब उसे वह अलौकिक आनंद मिलता है जो मानवीय सुखों से कहीं ऊपर है।",
  "374": "जब भी साधक शरीर और चित्त की अनित्यता का अनुभव करता है, उसे अपार प्रसन्नता होती है। ज्ञानियों के लिए यही अमृत है।",
  "375": "बुद्धिमान भिक्षु के लिए शुरुआत यहीं से होती है: इंद्रियों का संयम, संतोष और अनुशासन के नियमों का पालन।",
  "376": "सच्चे और परिश्रमी मित्रों का साथ करें। शिष्टाचार और व्यवहार में कुशल बनें। इससे प्रसन्नता बढ़ेगी और दुःखों का अंत होगा।",
  "377": "जैसे जूही का पौधा अपने सूखे फूलों को गिरा देता है, वैसे ही हे भिक्षुओ! तुम भी अपने भीतर से राग और द्वेष को गिरा दो।",
  "378": "जिसकी वाणी, शरीर और मन शांत हैं, जो पूरी तरह संयमित है और जिसने सांसारिक प्रलोभनों को त्याग दिया है, वही 'उपशांत' कहलाता है।",
  "379": "स्वयं को स्वयं ही प्रेरित करो और अपनी जाँच स्वयं करो। आत्म-सुरक्षित और सचेत रहकर ही तुम सुखपूर्वक जीवन जी सकोगे।",
  "380": "मनुष्य स्वयं ही अपना स्वामी और स्वयं ही अपनी शरण है। इसलिए स्वयं को वैसे ही साधें जैसे व्यापारी अपने अच्छे घोड़ों को साधता है।",
  "381": "बुद्ध की शिक्षाओं में आनंद लेने वाला प्रसन्न भिक्षु समस्त विकारों की शांति से प्राप्त होने वाले सुखद निर्वाण पद को पाता है।",
  "382": "जो युवा साधक बुद्ध के मार्ग पर समर्पित हो जाता है, वह बादलों से मुक्त चंद्रमा की भाँति इस संसार को प्रकाशित करता है।",
  "chap26": "ब्राह्मण",
  "383": "हे ब्राह्मण! साहस कर तृष्णा की धारा को काट दे और कामनाओं को दूर कर। जब तू जान लेगा कि सब कुछ अनित्य है, तब तू सत्य को जान लेगा।",
  "384": "जब ब्राह्मण एकाग्रता और विपश्यनाइन दो धर्मों में पारंगत हो जाता है, तब उसके सभी बंधन स्वयं ही नष्ट हो जाते हैं।",
  "385": "जिसके लिए न 'यह पार' है न 'वह पार', जो पूरी तरह निर्भय और अनासक्त है, उसे ही मैं ब्राह्मण कहता हूँ।",
  "386": "जो ध्यानी, निर्मल, स्थिर और अपने कर्तव्यों को पूर्ण कर चुका है, जो विकारों से मुक्त है और जिसने परम सत्य को पा लिया है, उसे ही मैं ब्राह्मण कहता हूँ।",
  "387": "सूर्य दिन में तपता है, चंद्रमा रात में चमकता है, योद्धा अपने कवच में शोभा पाता है, ब्राह्मण अपने ध्यान में तेजस्वी लगता है, किंतु बुद्ध अपनी आभा से दिन-रात प्रकाशमान रहते हैं।",
  "388": "ब्राह्मण वह है जिसने पाप बहा दिए हैं, श्रमण वह है जो समता में जीता है और प्रव्रजित वह है जिसने अपने चित्त की मलिनता त्याग दी है।",
  "389": "किसी निर्दोष ब्राह्मण पर प्रहार नहीं करना चाहिए और ब्राह्मण को भी प्रहार करने वाले पर क्रोध नहीं करना चाहिए। धिक्कार है ब्राह्मण के हन्ता पर, और उससे भी अधिक धिक्कार उसे जो बदले में क्रोध करता है।",
  "390": "ब्राह्मण के लिए सबसे श्रेष्ठ यही है कि वह अपने मन को प्रियों से हटा ले। जहाँ-जहाँ मन हिंसा से विमुख होता है, वहीं दुःख शांत हो जाता है।",
  "391": "जो शरीर, वाणी और मन से कोई बुरा कार्य नहीं करता और इन तीनों पर संयम रखता है, उसे ही मैं ब्राह्मण कहता हूँ।",
  "392": "जिससे भी बुद्ध का धर्म सीखने को मिले, उसे वैसे ही सम्मान दें जैसे ब्राह्मण अग्नि की पूजा करते हैं।",
  "393": "न जटाओं से, न ऊँचे कुल से और न जन्म से कोई ब्राह्मण होता है। जिसमें सत्य और धर्म का वास है, वही पवित्र है और वही वास्तव में ब्राह्मण है।",
  "394": "हे मूर्ख! इन बाहरी जटाओं और मृगचर्म से क्या लाभ? तेरा भीतर तो विकारों से भरा है, तू बाहर से शरीर को ही क्यों माँजता रहता है?",
  "395": "जो फटे-पुराने वस्त्र पहनता है, जिसका शरीर दुबला है और नसें दिखाई देती हैं, पर जो जंगल में अकेला ध्यान करता है, उसे ही मैं ब्राह्मण कहता हूँ।",
  "396": "मैं किसी को मात्र इसलिए ब्राह्मण नहीं कहता कि वह ऊँचे कुल में जन्मा है। यदि वह आसक्ति युक्त है तो वह केवल 'भो-वादी' है। ब्राह्मण वही है जो पूरी तरह अनासक्त और अपरिग्रही है।",
  "397": "जिसने सारे बंधनों को काटकर भय को जीत लिया है, जो संसार की पकड़ से बाहर निकल गया है, उसे ही मैं ब्राह्मण कहता हूँ।",
  "398": "जिसने क्रोध की रस्सी, तृष्णा का बंधन और अविद्या का जुआ उतार फेंका है, जो जागृत बुद्ध हो चुका है, उसे ही मैं ब्राह्मण कहता हूँ।",
  "399": "जो बिना मन मैला किए गाली, दंड और कारावास को सह लेता है, क्षमा ही जिसकी सबसे बड़ी सेना है, उसे ही मैं ब्राह्मण कहता हूँ।",
  "400": "जो क्रोधरहित, शीलवान, विनम्र और संयमित है, जिसका यह अंतिम जन्म है, उसे ही मैं ब्राह्मण कहता हूँ।",
  "401": "जैसे कमल के पत्ते पर पानी की बूँद और सूई की नोक पर सरसों का दाना नहीं ठहरता, वैसे ही जो कामभोगों में लिप्त नहीं होता, उसे मैं ब्राह्मण कहता हूँ।",
  "402": "जो इसी लोक में अपने दुःखों के अंत को प्रज्ञापूर्वक जान लेता है, जिसने मोह का बोझ उतार फेंका है और जो पूरी तरह आसक्तिरहित है, उसे मैं ब्राह्मण कहता हूँ।",
  "403": "गहन प्रज्ञा वाले, मेधावी, सही और गलत मार्ग के पारखी तथा परम लक्ष्य निर्वाण को प्राप्त महापुरुष को मैं ब्राह्मण कहता हूँ।",
  "404": "जो गृहस्थों और संन्यासियोंदोनों के संग से मुक्त है, जो बिना किसी ठौर-ठिकाने के विचरण करता है और जिसकी इच्छाएँ अल्प हैं, उसे मैं ब्राह्मण कहता हूँ।",
  "405": "चर और अचर सभी प्राणियों के प्रति जिसने हिंसा का त्याग कर दिया है, जो न स्वयं किसी की हत्या करता है और न दूसरों को हत्या के लिए प्रेरित करता है, उसे मैं ब्राह्मण कहता हूँ।",
  "406": "जो विरोधियों के बीच अविरोधी रहता है, शस्त्रधारियों के बीच जो शांत बना रहता है और संग्रह करने वालों के बीच जो पूर्णतः अपरिग्रही है, उसे मैं ब्राह्मण कहता हूँ।",
  "407": "जिसके चित्त से राग, द्वेष, अभिमान और ईर्ष्या वैसे ही गिर गए हैं जैसे सूई की नोक से सरसों का दाना, उसे मैं ब्राह्मण कहता हूँ।",
  "408": "जो ऐसी मधुर, सार्थक और सत्य वाणी बोलता है जिससे किसी को तनिक भी पीड़ा न पहुँचे, उसे मैं ब्राह्मण कहता हूँ।",
  "409": "जो इस संसार में लंबी या छोटी, मोटी या महीन, अच्छी या बुरीकिसी भी पराई वस्तु को बिना दिए नहीं लेता, उसे मैं ब्राह्मण कहता हूँ।",
  "410": "जिसके मन में इस लोक या परलोक के प्रति कोई लालसा नहीं रह गई है, जो सभी प्रकार की इच्छाओं और कामनाओं से मुक्त हो चुका है, उसे मैं ब्राह्मण कहता हूँ।",
  "411": "जिसमें कोई तृष्णा शेष नहीं है, जो परम सत्य को जानकर संदेहरहित हो गया है और जिसने निर्वाण के अमृत को पा लिया है, उसे मैं ब्राह्मण कहता हूँ।",
  "412": "जो इस संसार में पुण्य और पापदोनों के बंधनों से ऊपर उठ गया है, जो शोकरहित, निर्मल और शुद्ध है, उसे मैं ब्राह्मण कहता हूँ।",
  "413": "जो चंद्रमा की भाँति निष्कलंक, शुद्ध, प्रसन्न और मलरहित है और जिसकी जन्म लेने की तृष्णा पूरी तरह समाप्त हो गई है, उसे मैं ब्राह्मण कहता हूँ।",
  "414": "जिसने इस दुर्गम संसार और मोह के भ्रामक मार्ग को पार कर लिया है, जो ध्यानी, संदेहरहित और स्थिर चित्त होकर निर्वाण को प्राप्त कर चुका है, उसे मैं ब्राह्मण कहता हूँ।",
  "415": "जो इस संसार में कामभोगों का त्याग कर और घर-बार छोड़कर संन्यासी हो गया है, जिसकी भोग-इच्छा पूरी तरह नष्ट हो गई है, उसे मैं ब्राह्मण कहता हूँ।",
  "416": "जो इस लोक में तृष्णा को त्याग कर और गृह-त्याग कर प्रव्रजित हो गया है, जिसकी तृष्णा पूरी तरह क्षीण हो गई है, उसे मैं ब्राह्मण कहता हूँ।",
  "417": "जो मानवीय और दैवीयसभी प्रकार के बंधनों से ऊपर उठ गया है और जो हर बंधन से विमुक्त है, उसे मैं ब्राह्मण कहता हूँ।",
  "418": "जो सुख और दुख, आसक्ति और विरक्ति से परे होकर शांत और क्लेशरहित हो गया है, जिसने समस्त लोकों को जीत लिया है, उस वीर को मैं ब्राह्मण कहता हूँ।",
  "419": "जो प्राणियों के मरने और पुनः जन्म लेने के रहस्य को पूरी तरह जानता है, जो अनासक्त और बुद्धत्व से संपन्न है, उसे मैं ब्राह्मण कहता हूँ।",
  "420": "जिसकी अवस्था को देव, गंधर्व या मनुष्य भी नहीं जान सकते और जो विकारों से मुक्त अरहंत है, उसे मैं ब्राह्मण कहता हूँ।",
  "421": "जो अतीत, भविष्य और वर्तमान की सभी कामनाओं से मुक्त है, जिसके पास अपना कहने को कुछ नहीं और जो पूरी तरह अपरिग्रही है, उसे मैं ब्राह्मण कहता हूँ।",
  "422": "जो श्रेष्ठ, वीर, महर्षि, विजेता, अचल, निष्पाप और बुद्ध है, उसे मैं ब्राह्मण कहता हूँ।",
  "423": "जो अपने पूर्व जन्मों को जानता है, जो स्वर्ग और नरक को देख लेता है और जो जन्म-मरण के चक्र से मुक्त होकर पूर्णता को प्राप्त मुनि है, उसे मैं ब्राह्मण कहता हूँ।"
};
